INSERT INTO gba_games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 668, 'Pokémon Emerald Version', 'Game Boy Advance', 5, 35078, 35078, 35078, 197, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo', '2004-09-16', 'Pokémon Emerald Version is a 2004 role-playing video game developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. It was first released in Japan in 2004, and was later released internationally in 2005. It is the fifth version, after both Pokémon Ruby and Sapphire and Pokémon FireRed and LeafGreen, and is the final game of the third generation of the Pokémon video game series.', 'https://media.retroachievements.org/Images/104473.png', 'https://media.retroachievements.org/Images/014406.png', 'https://media.retroachievements.org/Images/005442.png', 'https://media.retroachievements.org/Images/077264.png', 5),
  (2, 534, 'Metroid: Zero Mission', 'Game Boy Advance', 5, 31244, 31244, 31244, 55, 0, 'Metroidvania', NULL, 'Nintendo', '2004-02-09', 'Metroid: Zero Mission is a 2004 action-adventure game developed and published by Nintendo for the Game Boy Advance. It is a remake of the original Metroid (1986), with updated visuals and gameplay.', 'https://media.retroachievements.org/Images/093574.png', 'https://media.retroachievements.org/Images/096231.png', 'https://media.retroachievements.org/Images/000655.png', 'https://media.retroachievements.org/Images/065313.png', 5),
  (3, 510, 'Castlevania: Aria of Sorrow', 'Game Boy Advance', 5, 28476, 28476, 28476, 66, 0, '2D Platforming, Action RPG, Metroidvania', 'Konami', 'Konami', '2003-05-06', 'Castlevania: Aria of Sorrow is a 2003 action role-playing game developed by Konami Computer Entertainment Tokyo and published by Konami for the Game Boy Advance. It is the 20th main entry in the Castlevania series, as well as the third and final game produced for the system. Producer Koji Igarashi, who had led the production teams for previous Castlevania games, led Aria of Sorrow''s development as well. Michiru Yamane returned to compose the music alongside Takashi Yoshida and Soshiro Hokkai. Director Junichi Murakami was new to the Castlevania series.', 'https://media.retroachievements.org/Images/085857.png', 'https://media.retroachievements.org/Images/071775.png', 'https://media.retroachievements.org/Images/071777.png', 'https://media.retroachievements.org/Images/071776.png', 5),
  (4, 515, 'Pokémon FireRed Version', 'Game Boy Advance', 5, 25947, 25947, 25947, 61, 0, 'Turn-Based RPG', 'Game Freak', 'Nintendo', '2004-01-29', 'Pokémon FireRed Version and Pokémon LeafGreen Version are 2004 remakes of the 1996 role-playing video games Pokémon Red and Blue. They were developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. FireRed and LeafGreen were first released in Japan in January 2004 and in North America and Europe in September and October 2004, respectively. The games are part of the third generation of the Pokémon video game series and hold the distinction of being the first enhanced remakes of previous games within the franchise.', 'https://media.retroachievements.org/Images/105044.png', 'https://media.retroachievements.org/Images/001918.png', 'https://media.retroachievements.org/Images/001917.png', 'https://media.retroachievements.org/Images/111883.png', 4.9),
  (5, 559, 'The Legend of Zelda: The Minish Cap', 'Game Boy Advance', 5, 21579, 21579, 21579, 66, 0, 'Action-Adventure', 'Capcom', 'Nintendo', '2004-11-04', 'The Legend of Zelda: The Minish Cap is a 2004 action-adventure game developed by Capcom and Flagship and published by Nintendo for the Game Boy Advance. The twelfth entry in The Legend of Zelda series, The Minish Cap was released for the Game Boy Advance in Japan and Europe in 2004 and in North America and Australia the following year.', 'https://media.retroachievements.org/Images/113471.png', 'https://media.retroachievements.org/Images/000156.png', 'https://media.retroachievements.org/Images/033839.png', 'https://media.retroachievements.org/Images/000049.png', 4.9),
  (6, 770, 'Kirby: Nightmare in Dream Land', 'Game Boy Advance', 5, 19218, 19218, 19218, 70, 0, NULL, 'HAL Laboratory', 'Nintendo', '2002-10-25', 'Kirby''s Adventure is a 1993 platform game developed by HAL Laboratory and published by Nintendo for the Nintendo Entertainment System (NES). It is the second game in the Kirby series after Kirby''s Dream Land (1992) on the Game Boy and the first to include the Copy Ability, which allows the main character Kirby to gain new powers by eating certain enemies. The game centers around Kirby traveling across Dream Land to repair the Star Rod after King Dedede breaks it apart and gives the pieces to his minions.', 'https://media.retroachievements.org/Images/122187.png', 'https://media.retroachievements.org/Images/124461.png', 'https://media.retroachievements.org/Images/033745.png', 'https://media.retroachievements.org/Images/002594.png', 4.9),
  (7, 802, 'WarioWare, Inc.: Mega Microgame$!', 'Game Boy Advance', 5, 18393, 18393, 18393, 47, 0, 'Minigames', NULL, 'Nintendo', '2003-03-21', 'WarioWare, Inc.: Mega Microgames!, known as WarioWare, Inc.: Minigame Mania in PAL regions, is a 2003 action game developed and published by Nintendo for the Game Boy Advance. The debut title in the WarioWare series, the game is about rapid completion of "microgames", short minigames given to the player consecutively and with increasing speed per each game complete. The game''s concept was inspired by the "Sound Bomber" mode of Mario Artist: Polygon Studio for the Nintendo 64DD. Many of the music tracks and sound effects were recycled from Wario Land 4. The game was produced by Takehiro Izushi and directed by Hirofumi Matsuoka. Matsuoka was also the director of Polygon Studio. Mega Microgames! was released in 2003; in Japan in March, in North America and Europe in May and in Australia in June.', 'https://media.retroachievements.org/Images/105321.png', 'https://media.retroachievements.org/Images/089239.png', 'https://media.retroachievements.org/Images/109611.png', 'https://media.retroachievements.org/Images/109612.png', 4.8),
  (8, 793, 'Sonic Advance', 'Game Boy Advance', 5, 18115, 18115, 18115, 58, 0, '2D Platforming', 'Dimps, Sonic Team', 'Sega, THQ', '2001-12-20', 'Sonic Advance is a 2001 platform game developed by Sonic Team and Dimps and published by Sega for the Game Boy Advance. It was one of the first Sonic the Hedgehog games to be released on a Nintendo console along with Sonic Adventure 2: Battle on the GameCube, and was produced in commemoration of the series'' tenth anniversary. The story follows Sonic, Tails, Knuckles, and Amy as they journey to stop Doctor Eggman from taking over the world. Controlling a character, players are tasked with completing each level, defeating Eggman and his robot army, and collecting the seven Chaos Emeralds.', 'https://media.retroachievements.org/Images/044233.png', 'https://media.retroachievements.org/Images/119088.png', 'https://media.retroachievements.org/Images/003925.png', 'https://media.retroachievements.org/Images/064085.png', 4.8),
  (9, 17530, '~Hack~ Pokémon Unbound', 'Game Boy Advance', 5, 16333, 16333, 16333, 129, 0, 'Turn-Based RPG', 'Skeli', NULL, '2020-12-01', 'The following is a list of notable vehicle racing video games. The genre first emerged in the mid- to late 1970s.', 'https://media.retroachievements.org/Images/073204.png', 'https://media.retroachievements.org/Images/067057.png', 'https://media.retroachievements.org/Images/069748.png', 'https://media.retroachievements.org/Images/042903.png', 4.8),
  (10, 771, 'Mario & Luigi: Superstar Saga', 'Game Boy Advance', 5, 15368, 15368, 15368, 85, 0, 'Turn-Based RPG', 'AlphaDream', 'Nintendo', '2003-11-17', 'Mario & Luigi: Superstar Saga is a 2003 role-playing video game developed by AlphaDream and published by Nintendo for the Game Boy Advance. It is the first game in the Mario & Luigi series. The story follows Mario and Luigi as they travel to the Beanbean Kingdom in order to combat Cackletta and Fawful, who stole Princess Peach''s voice for the purpose of harnessing the power of a special artifact called the Beanstar.', 'https://media.retroachievements.org/Images/116411.png', 'https://media.retroachievements.org/Images/014492.png', 'https://media.retroachievements.org/Images/071816.png', 'https://media.retroachievements.org/Images/002111.png', 4.8),
  (11, 745, 'Castlevania: Circle of the Moon', 'Game Boy Advance', 5, 15104, 15104, 15104, 109, 0, '2D Platforming, Metroidvania', 'Konami', 'Konami', '2001-03-21', 'Castlevania: Circle of the Moon, titled Castlevania in PAL regions, is a 2001 action role-playing game developed and published by Konami for the Game Boy Advance handheld game console. The game was developed as a stand-alone title in the Castlevania series and as a launch title for the Game Boy Advance.', 'https://media.retroachievements.org/Images/105343.png', 'https://media.retroachievements.org/Images/072393.png', 'https://media.retroachievements.org/Images/071781.png', 'https://media.retroachievements.org/Images/071782.png', 4.8),
  (12, 789, 'Pokémon Pinball: Ruby & Sapphire', 'Game Boy Advance', 5, 14227, 14227, 14227, 54, 0, 'Pinball', 'Jupiter', 'Nintendo', '2003-08-01', 'Pokémon Pinball: Ruby & Sapphire is a 2003 pinball game developed by Jupiter and published by The Pokémon Company and Nintendo for the Game Boy Advance handheld game console. It was first revealed at E3 2003. The North American release was done to coincide with the fifth anniversary of the North American release of Pokémon Red and Blue. It is based on Pokémon Ruby and Sapphire, and is a sequel to Pokémon Pinball for the Game Boy Color. In some ways, it plays like a traditional pinball game, where the objective is to get a high score by keeping the ball in play as long as possible and hitting bumpers. In keeping with the theme of Pokémon, it features Pokémon collection, where while the players play pinball, they must also capture the eponymous creatures.', 'https://media.retroachievements.org/Images/092736.png', 'https://media.retroachievements.org/Images/000660.png', 'https://media.retroachievements.org/Images/000658.png', 'https://media.retroachievements.org/Images/077265.png', 4.8),
  (13, 769, 'Kirby & The Amazing Mirror', 'Game Boy Advance', 5, 13512, 13512, 13512, 54, 0, '2D Platforming, Metroidvania', 'HAL Laboratory, Flagship, Dimps', 'Nintendo', '2004-04-15', 'Kirby & The Amazing Mirror is a 2004 platform game developed by HAL Laboratory, Flagship and Dimps and published by Nintendo for the Game Boy Advance. The seventh mainline Kirby entry, the game is notable for its unique Metroidvania playstyle and being the first in the genre to support cooperative four-player multiplayer, and follows Kirby as he goes on a journey through the Mirror Dimension to reassemble a mirror after Dark Meta Knight traps Meta Knight inside it.', 'https://media.retroachievements.org/Images/042405.png', 'https://media.retroachievements.org/Images/014483.png', 'https://media.retroachievements.org/Images/118666.png', 'https://media.retroachievements.org/Images/118667.png', 4.8),
  (14, 580, 'The Legend of Zelda: A Link to the Past & Four Swords', 'Game Boy Advance', 5, 13240, 13240, 13240, 62, 0, 'Action-Adventure', 'Capcom', 'Nintendo', '2003-12-02', 'The Legend of Zelda: A Link to the Past and Four Swords is a 2002 action-adventure game compilation developed by Nintendo R&D2 and Flagship and published by Nintendo for the Game Boy Advance. The game was released in December 2002 in North America and in March 2003 in Japan and Europe. The cartridge contains a modified port of A Link to the Past, originally released for the Super Nintendo Entertainment System in 1991, and an original multiplayer-only game titled Four Swords, which serves as the ninth installment in The Legend of Zelda series.', 'https://media.retroachievements.org/Images/063671.png', 'https://media.retroachievements.org/Images/022503.png', 'https://media.retroachievements.org/Images/033841.png', 'https://media.retroachievements.org/Images/000078.png', 4.8),
  (15, 767, 'Golden Sun', 'Game Boy Advance', 5, 12203, 12203, 12203, 60, 0, 'Turn-Based RPG', 'Camelot Software Planning', 'Nintendo', '2001-11-11', 'Golden Sun is a series of fantasy role-playing video games developed by Camelot Software Planning and published by Nintendo. It follows the story of a group of magically attuned "adepts" who are charged with preventing the potentially destructive power of alchemy from being released as it was in the past. Players navigate characters through the game''s world by defeating enemies, solving puzzles, and completing assigned missions to complete the storyline.', 'https://media.retroachievements.org/Images/059231.png', 'https://media.retroachievements.org/Images/067993.png', 'https://media.retroachievements.org/Images/033743.png', 'https://media.retroachievements.org/Images/006544.png', 4.7),
  (16, 526, 'Crash Bandicoot: The Huge Adventure', 'Game Boy Advance', 5, 9246, 9246, 9246, 74, 0, '2D Platforming', 'Vicarious Visions', 'Universal Interactive', '2002-02-26', 'Crash Bandicoot: The Huge Adventure is a 2002 platform game developed by Vicarious Visions and published by Universal Interactive for the Game Boy Advance. It is the seventh installment in the Crash Bandicoot video game series, the first Crash Bandicoot game not to be released on a PlayStation console, and the first Crash Bandicoot game to be released on a handheld console. The game''s story centers on a plot to shrink the Earth by the main antagonist, Doctor Neo Cortex, through the use of a gigantic weapon named the "Planetary Minimizer". The protagonist of the story, Crash Bandicoot, must gather Crystals in order to power a device that will return the Earth to its proper size, defeating Cortex and his minions along the way.', 'https://media.retroachievements.org/Images/081317.png', 'https://media.retroachievements.org/Images/096395.png', 'https://media.retroachievements.org/Images/004381.png', 'https://media.retroachievements.org/Images/070480.png', 4.7),
  (17, 782, 'Mega Man Zero', 'Game Boy Advance', 5, 8811, 8811, 8811, 44, 0, '2D Platforming, Action', 'Inti Creates', 'Capcom', '2002-04-26', 'Mega Man Zero is a hack and slash platform game series in Capcom''s Mega Man video game franchise. It was developed by Inti Creates, with Co-Producer Keiji Inafune and Director Yoshinori Kawano. The series consists of four games that were first released on the Game Boy Advance and later on the Nintendo DS and the Virtual Console.', 'https://media.retroachievements.org/Images/025922.png', 'https://media.retroachievements.org/Images/001879.png', 'https://media.retroachievements.org/Images/001877.png', 'https://media.retroachievements.org/Images/001878.png', 4.7),
  (18, 677, 'Mother 3', 'Game Boy Advance', 5, 8772, 8772, 8772, 132, 0, 'Turn-Based RPG', 'Brownie Brown, HAL Laboratory', 'Nintendo', '2006-04-20', 'Mother 3 is a 2006 role-playing video game developed by Brownie Brown and HAL Laboratory and published by Nintendo for the Game Boy Advance. It is the third and final entry in the Mother series. The game follows Lucas, a young boy with psychic abilities, and a party of characters as they attempt to prevent a mysterious invading army from corrupting and destroying the world.', 'https://media.retroachievements.org/Images/122954.png', 'https://media.retroachievements.org/Images/046366.png', 'https://media.retroachievements.org/Images/001812.png', 'https://media.retroachievements.org/Images/001813.png', 4.7),
  (19, 5068, 'Alien Hominid', 'Game Boy Advance', 5, 8472, 8472, 8472, 26, 0, 'Run & Gun', 'Tuna Technologies', 'Zoo Digital Publishing | Zushi Games', '2006-02-03', 'Alien Hominid is a run and gun video game developed by The Behemoth and first released as a Flash game on the multimedia website Newgrounds on August 7, 2002. It was originally developed in Adobe Flash by programmer and Newgrounds founder, Tom Fulp, and animator and artist, Dan Paladin. An expanded console version released on the PlayStation 2, GameCube and Xbox across 2004 and 2005. A port for the Game Boy Advance, developed by Tuna Technologies, was released in 2006 for PAL regions. A high-definition version titled Alien Hominid 360 was released for Xbox 360 via Xbox Live Arcade in 2007. Another remaster, Alien Hominid HD, was released for Windows, Nintendo Switch, Xbox One and Xbox Series X/S alongside its sequel, Alien Hominid Invasion, in 2023, and again in 2025 for PlayStation 4 and PlayStation 5.', 'https://media.retroachievements.org/Images/067756.png', 'https://media.retroachievements.org/Images/014430.png', 'https://media.retroachievements.org/Images/003123.png', 'https://media.retroachievements.org/Images/003125.png', 4.7),
  (20, 750, 'Donkey Kong Country', 'Game Boy Advance', 5, 7911, 7911, 7911, 80, 0, '2D Platforming', 'Rare', 'Nintendo', '2003-06-09', 'Donkey Kong Country, known in Japan as Super Donkey Kong, is a 1994 platform game developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It follows the gorilla Donkey Kong and his nephew Diddy Kong as they set out to recover their stolen banana hoard from the crocodile King K. Rool and his army, the Kremlings. The player traverses 40 side-scrolling levels as they jump between platforms and avoid obstacles. They collect items, ride minecarts and animals, defeat enemies and bosses, and find secret bonus stages. In multiplayer modes, two players work cooperatively or race.', 'https://media.retroachievements.org/Images/072187.png', 'https://media.retroachievements.org/Images/014451.png', 'https://media.retroachievements.org/Images/083145.png', 'https://media.retroachievements.org/Images/083146.png', 4.6),
  (21, 2816, 'Pokémon Mystery Dungeon: Red Rescue Team', 'Game Boy Advance', 5, 7204, 7204, 7204, 128, 0, 'Roguelike', 'Chunsoft', 'Nintendo', '2005-11-17', 'Pokémon Mystery Dungeon: Blue Rescue Team and Pokémon Mystery Dungeon: Red Rescue Team are a matched pair of Pokémon video games for the Nintendo DS and Game Boy Advance, respectively. The games were developed by Chunsoft and published by The Pokémon Company and Nintendo. Red Rescue Team was the last Pokémon game released for the Game Boy Advance. The two versions are mostly identical, with Blue Rescue Team taking advantage of the dual-screen features and increased graphical and sound capabilities of the Nintendo DS. The game has six Pokémon exclusive to each version. Mystery Dungeon is quite different than the main-line games, as in the Mystery Dungeon games, you play as a Pokémon, as opposed to playing as a trainer.', 'https://media.retroachievements.org/Images/050264.png', 'https://media.retroachievements.org/Images/021995.png', 'https://media.retroachievements.org/Images/068561.png', 'https://media.retroachievements.org/Images/068563.png', 4.6),
  (22, 2445, 'Mario Pinball Land', 'Game Boy Advance', 5, 7195, 7195, 7195, 68, 0, 'Pinball', 'Fuse Games | Silverball Studios', 'Nintendo', '2004-08-26', 'Mario Pinball Land, known in Europe and Japan as Super Mario Ball, is a 2004 pinball video game developed by Fuse Games and published by Nintendo for the Game Boy Advance. It is a spin-off of the Super Mario series. The game was later re-released for the Wii U Virtual Console.', 'https://media.retroachievements.org/Images/034679.png', 'https://media.retroachievements.org/Images/071266.png', 'https://media.retroachievements.org/Images/003675.png', 'https://media.retroachievements.org/Images/003676.png', 4.6),
  (23, 554, 'Fire Emblem: The Blazing Blade', 'Game Boy Advance', 5, 6965, 6965, 6965, 87, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2003-11-03', 'Fire Emblem: The Blazing Blade, also known simply as Fire Emblem, is a 2003 tactical role-playing game developed by Intelligent Systems and published by Nintendo for the Game Boy Advance. It is the seventh installment in the Fire Emblem series, the second to be released for the platform after Fire Emblem: The Binding Blade, and the first to be localized for international audiences. It was released in Japan and North America in 2003, and in Europe and Australia in 2004.', 'https://media.retroachievements.org/Images/042758.png', 'https://media.retroachievements.org/Images/089241.png', 'https://media.retroachievements.org/Images/033779.png', 'https://media.retroachievements.org/Images/005927.png', 4.6),
  (24, 790, 'Pokémon Ruby Version', 'Game Boy Advance', 5, 6964, 6964, 6964, 49, 0, NULL, NULL, NULL, '2002-11-21', 'Pokémon Ruby Version and Pokémon Sapphire Version are 2002 role-playing video games developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. They are the first installments in the third generation of the Pokémon video game series, also known as the "advanced generation". After years of Nintendo being the sole publisher of the franchise in all regions, The Pokémon Company co-published the games for the first time since the establishment of the joint-owned company in 1998. They were first released in Japan in late 2002, and internationally in 2003. Pokémon Emerald, a third version, was released two years later in each region. Remakes of the two games, titled Pokémon Omega Ruby and Alpha Sapphire, were released for the Nintendo 3DS worldwide in November 2014, exactly twelve years to the date of the original Ruby and Sapphire release date, with the exception of Europe, where it released a week later.', 'https://media.retroachievements.org/Images/104260.png', 'https://media.retroachievements.org/Images/077260.png', 'https://media.retroachievements.org/Images/014934.png', 'https://media.retroachievements.org/Images/077261.png', 4.6),
  (25, 1376, 'Dragon Ball: Advanced Adventure', 'Game Boy Advance', 5, 6669, 6669, 6669, 44, 0, '2D Platforming, Beat ''em Up', 'Dimps', 'Atari, Bandai, Banpresto', '2004-11-18', 'Dragon Ball: Advanced Adventure is a 2004 video game released for Game Boy Advance based on the Dragon Ball franchise.', 'https://media.retroachievements.org/Images/051641.png', 'https://media.retroachievements.org/Images/112816.png', 'https://media.retroachievements.org/Images/009003.png', 'https://media.retroachievements.org/Images/009004.png', 4.6),
  (26, 557, 'Sonic Advance 2', 'Game Boy Advance', 5, 6456, 6456, 6456, 40, 0, '2D Platforming', 'Dimps, Sonic Team', 'Sega, THQ', '2002-12-19', 'Sonic Advance 2 is a 2002 platform game developed by Dimps and published by Sega for the Game Boy Advance. It is an installment in the Sonic the Hedgehog series and the sequel to 2001''s Sonic Advance. The story follows Sonic as he sets out to save his friends and retrieve the seven magical Chaos Emeralds from Dr. Eggman. Gameplay consists of the player completing various levels as one of five characters, each with their own unique attributes. After each zone is completed, the player faces Dr. Eggman in a boss battle.', 'https://media.retroachievements.org/Images/044234.png', 'https://media.retroachievements.org/Images/119087.png', 'https://media.retroachievements.org/Images/003937.png', 'https://media.retroachievements.org/Images/108905.png', 4.6),
  (27, 505, 'Super Mario Advance', 'Game Boy Advance', 5, 6344, 6344, 6344, 81, 0, '2D Platforming', 'Nintendo', 'Nintendo, iQue', '2001-03-21', 'Super Mario Advance is a 2001 platform game developed and published by Nintendo as a launch title for the Game Boy Advance (GBA). It is an enhanced remake of the NES video game Super Mario Bros. 2 (1988), using the graphical style of Super Mario All-Stars (1993). Players control Mario, Luigi, Peach, or Toad as they travel through the seven worlds of Subcon to save the kingdom from the evil toad Wart. It contains several additions, including voice clips for all playable characters, giant renditions of objects, and a multiplayer mode based on the original Mario Bros. arcade game.', 'https://media.retroachievements.org/Images/035249.png', 'https://media.retroachievements.org/Images/110910.png', 'https://media.retroachievements.org/Images/108511.png', 'https://media.retroachievements.org/Images/002834.png', 4.6),
  (28, 762, 'Final Fantasy I & II: Dawn of Souls', 'Game Boy Advance', 5, 6096, 6096, 6096, 69, 0, NULL, 'Square Enix', 'Nintendo, Square Enix', '2004-11-29', 'Final Fantasy is a 1987 role-playing video game developed and published by Square for the Nintendo Entertainment System. It is the first game in Square''s Final Fantasy series, created by Hironobu Sakaguchi. The story follows four youths called the Warriors of Light, who each carry one of their world''s four elemental crystals which have been darkened by the four Elemental Fiends. Together, they quest to defeat these evil forces, restore light to the crystals, and save their world.', 'https://media.retroachievements.org/Images/059662.png', 'https://media.retroachievements.org/Images/014469.png', 'https://media.retroachievements.org/Images/006118.png', 'https://media.retroachievements.org/Images/006119.png', 4.6),
  (29, 794, 'Sonic Advance 3', 'Game Boy Advance', 5, 6054, 6054, 6054, 63, 0, '2D Platforming', 'Dimps, Sonic Team', 'Sega, THQ', '2004-01-01', 'Sonic Advance 3 is a 2004 platform game developed by Sonic Team and Dimps and published by Sega for the Game Boy Advance. It is part of the Sonic the Hedgehog series, and the final sequel to Sonic Advance 2. The game stars the characters Sonic, Tails, Knuckles, Amy, and Cream as they seek to keep Doctor Eggman and his robot assistant Gemerl from building empires on each of seven chunks Eggman has divided the Earth into.', 'https://media.retroachievements.org/Images/044235.png', 'https://media.retroachievements.org/Images/045495.png', 'https://media.retroachievements.org/Images/003387.png', 'https://media.retroachievements.org/Images/003781.png', 4.6),
  (30, 758, 'Dragon Ball Z: The Legacy of Goku', 'Game Boy Advance', 5, 5762, 5762, 5762, 39, 0, 'Action RPG', 'Webfoot Technologies', 'Infogrames', '2002-05-14', 'Dragon Ball Z: The Legacy of Goku is a series of video games for the Game Boy Advance, based on the anime series Dragon Ball Z and part of the Dragon Ball video game series. All three games are action role-playing games. The first game, Dragon Ball Z: The Legacy of Goku, was developed by Webfoot Technologies and released in 2002. The game was followed by two sequels: Dragon Ball Z: The Legacy of Goku II, released in 2003, and Dragon Ball Z: Buu''s Fury, released in 2004. Buu''s Fury was re-released in 2006 as part of a Game Boy Advance two-pack, which includes Dragon Ball GT: Transformation on the same cartridge. In 2016, Webfoot Technologies claimed to be starting development of another sequel.', 'https://media.retroachievements.org/Images/093870.png', 'https://media.retroachievements.org/Images/095540.png', 'https://media.retroachievements.org/Images/095161.png', 'https://media.retroachievements.org/Images/095162.png', 4.6),
  (31, 791, 'Pokémon Sapphire Version', 'Game Boy Advance', 5, 4941, 4941, 4941, 49, 0, NULL, NULL, NULL, '2002-11-21', 'Pokémon Ruby Version and Pokémon Sapphire Version are 2002 role-playing video games developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. They are the first installments in the third generation of the Pokémon video game series, also known as the "advanced generation". After years of Nintendo being the sole publisher of the franchise in all regions, The Pokémon Company co-published the games for the first time since the establishment of the joint-owned company in 1998. They were first released in Japan in late 2002, and internationally in 2003. Pokémon Emerald, a third version, was released two years later in each region. Remakes of the two games, titled Pokémon Omega Ruby and Alpha Sapphire, were released for the Nintendo 3DS worldwide in November 2014, exactly twelve years to the date of the original Ruby and Sapphire release date, with the exception of Europe, where it released a week later.', 'https://media.retroachievements.org/Images/104257.png', 'https://media.retroachievements.org/Images/077257.png', 'https://media.retroachievements.org/Images/077263.png', 'https://media.retroachievements.org/Images/077262.png', 4.5),
  (32, 519, 'Final Fantasy Tactics Advance', 'Game Boy Advance', 5, 4771, 4771, 4771, 138, 0, 'Tactical RPG', 'Square Enix', 'Nintendo', '2003-09-08', 'Final Fantasy Tactics Advance is a 2003 tactical role-playing game developed by Square for the Game Boy Advance, and published by Square in Japan and Nintendo internationally. A successor to Final Fantasy Tactics (1997), the story follows the trials of some children from the town of St. Ivalice after a magical book transforms their home into a fantasy realm of the same name. Gameplay has player teams fighting in turn-based combat on a grid, with units using a themed Job system. A new feature is a "Law" system, which places random limitations on player action during battles.', 'https://media.retroachievements.org/Images/070805.png', 'https://media.retroachievements.org/Images/014472.png', 'https://media.retroachievements.org/Images/002838.png', 'https://media.retroachievements.org/Images/002980.png', 4.5),
  (33, 5081, 'Aladdin', 'Game Boy Advance', 5, 4662, 4662, 4662, 39, 0, '2D Platforming', 'Disney Interactive Studios', 'Capcom', '2004-09-28', 'Aladdin is a Middle-Eastern folk tale. It is one of the best-known tales associated with One Thousand and One Nights, despite not being part of the original text; it was added by the Frenchman Antoine Galland, based on a folk tale that he heard from the Syrian storyteller Hanna Diyab.', 'https://media.retroachievements.org/Images/121440.png', 'https://media.retroachievements.org/Images/096964.png', 'https://media.retroachievements.org/Images/009281.png', 'https://media.retroachievements.org/Images/009282.png', 4.5),
  (34, 30894, '~Hack~ Pokémon Emerald Seaglass', 'Game Boy Advance', 5, 4612, 4612, 4612, 68, 0, NULL, 'Nemo622', NULL, '2024-08-23', NULL, 'https://media.retroachievements.org/Images/101849.png', 'https://media.retroachievements.org/Images/120406.png', 'https://media.retroachievements.org/Images/104743.png', 'https://media.retroachievements.org/Images/104744.png', 4.5),
  (35, 30137, '~Hack~ Pokémon Emerald Rogue V2', 'Game Boy Advance', 5, 4360, 4360, 4360, 260, 0, 'Roguelike, Turn-Based RPG', 'Pokabbie', 'Hack - Pokemon Emerald Version', '2024-07-02', 'Nintendo is a Japanese multinational video game company headquartered in Kyoto. It develops, publishes, and manufactures both video games and video game consoles. The history of Nintendo began in 1889 when craftsman Fusajiro Yamauchi founded the company to produce handmade hanafuda playing cards. After venturing into various lines of business and becoming a public company, Nintendo began producing toys in the 1960s, and later video games.', 'https://media.retroachievements.org/Images/099243.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/099241.png', 'https://media.retroachievements.org/Images/099242.png', 4.5),
  (36, 4033, 'Rhythm Tengoku', 'Game Boy Advance', 5, 4331, 4331, 4331, 36, 0, 'Rhythm', NULL, 'Nintendo', '2006-08-03', 'Rhythm Tengoku is a 2006 rhythm game developed and published by Nintendo for the Game Boy Advance. It was originally released on August 3, 2006, as the last first-party game to be released for the console. The game began as an idea created by its composer and supervisor Tsunku, who proposed it to Nintendo due to his belief that they could do a better job with it than he could. An arcade version of the game was reprogrammed and published by Sega on September 20, 2007. Both versions were released in Japan exclusively. The game was the first in the Rhythm Heaven series which spawned three international sequels; Rhythm Heaven, Rhythm Heaven Fever, and Rhythm Heaven Megamix, with a fourth sequel, Rhythm Heaven Groove, set for release in 2026.', 'https://media.retroachievements.org/Images/047000.png', 'https://media.retroachievements.org/Images/002417.png', 'https://media.retroachievements.org/Images/002415.png', 'https://media.retroachievements.org/Images/002418.png', 4.5),
  (37, 2171, 'Mario Tennis: Power Tour', 'Game Boy Advance', 5, 4247, 4247, 4247, 58, 0, 'Sports - Tennis, Role-Playing Game', 'Camelot Software Planning', 'Nintendo', '2005-12-05', 'Mario Tennis: Power Tour, known as Mario Power Tennis in Europe, is a 2005 role-playing sports game developed by Camelot Software Planning and published by Nintendo for the Game Boy Advance. It is the sequel to the Game Boy Color version of Mario Tennis. While it is the handheld companion to Mario Power Tennis, released on GameCube, with the European release sharing its title, Power Tour lacks connectivity with Power Tennis, unlike how its predecessor features connectivity with its console counterpart on Nintendo 64. Power Tour was re-released on the Wii U''s Virtual Console in 2014.', 'https://media.retroachievements.org/Images/116617.png', 'https://media.retroachievements.org/Images/014496.png', 'https://media.retroachievements.org/Images/117351.png', 'https://media.retroachievements.org/Images/117352.png', 4.5),
  (38, 528, 'Doom', 'Game Boy Advance', 5, 4014, 4014, 4014, 83, 0, 'First-Person Shooter', 'id Software, David A. Palmer Productions', 'Activision', '2001-10-28', 'Doom is an American media franchise created by John Carmack, John Romero, Adrian Carmack, Kevin Cloud, and Tom Hall. The series usually focuses on the exploits of an unnamed space marine operating under the auspices of the Union Aerospace Corporation (UAC), who fights hordes of demons and the undead to save Earth from an apocalyptic invasion.', 'https://media.retroachievements.org/Images/035909.png', 'https://media.retroachievements.org/Images/014455.png', 'https://media.retroachievements.org/Images/088173.png', 'https://media.retroachievements.org/Images/088172.png', 4.5),
  (39, 514, 'Metal Slug Advance', 'Game Boy Advance', 5, 3911, 3911, 3911, 23, 0, 'Run & Gun', 'Noise Factory', 'SNK', '2004-11-12', 'Metal Slug Advance is a run and gun video game for the Game Boy Advance handheld system created by SNK Playmore in 2004, and is canon to the Metal Slug series.', 'https://media.retroachievements.org/Images/049736.png', 'https://media.retroachievements.org/Images/069381.png', 'https://media.retroachievements.org/Images/001032.png', 'https://media.retroachievements.org/Images/001033.png', 4.5),
  (40, 2188, 'Sonic Battle', 'Game Boy Advance', 5, 3874, 3874, 3874, 30, 0, 'Arena Fighting', 'Sega, Sonic Team', 'THQ', '2003-12-03', 'Sonic Battle is a 2003 Fighting game developed by Sonic Team and published by Sega for the Game Boy Advance. It is the second fighting game in the Sonic the Hedgehog series, the first game being Sonic the Fighters. It was released in Japan in December 2003 and in North America and Europe in early 2004. The game received an indifferent response from critics.', 'https://media.retroachievements.org/Images/042714.png', 'https://media.retroachievements.org/Images/111785.png', 'https://media.retroachievements.org/Images/007053.png', 'https://media.retroachievements.org/Images/007054.png', 4.5),
  (41, 5077, 'Gunstar Super Heroes', 'Game Boy Advance', 5, 3854, 3854, 3854, 57, 0, 'Run & Gun', 'Treasure', 'Sega', '2005-10-06', 'Gunstar Super Heroes is a run and gun video game for the Game Boy Advance developed by Treasure and published by Sega in 2005. It is the sequel to the 1993 Sega Genesis game Gunstar Heroes, with the story taking place after the events of the original game and featuring an expanded combat system over its predecessor.', 'https://media.retroachievements.org/Images/079539.png', 'https://media.retroachievements.org/Images/005855.png', 'https://media.retroachievements.org/Images/033780.png', 'https://media.retroachievements.org/Images/005856.png', 4.5),
  (42, 759, 'Dragon Ball Z: The Legacy of Goku II', 'Game Boy Advance', 5, 3549, 3549, 3549, 57, 0, 'Action RPG', 'Webfoot Technologies', 'Atari', '2003-06-17', 'Dragon Ball Z: The Legacy of Goku is a series of video games for the Game Boy Advance, based on the anime series Dragon Ball Z and part of the Dragon Ball video game series. All three games are action role-playing games. The first game, Dragon Ball Z: The Legacy of Goku, was developed by Webfoot Technologies and released in 2002. The game was followed by two sequels: Dragon Ball Z: The Legacy of Goku II, released in 2003, and Dragon Ball Z: Buu''s Fury, released in 2004. Buu''s Fury was re-released in 2006 as part of a Game Boy Advance two-pack, which includes Dragon Ball GT: Transformation on the same cartridge. In 2016, Webfoot Technologies claimed to be starting development of another sequel.', 'https://media.retroachievements.org/Images/093985.png', 'https://media.retroachievements.org/Images/095539.png', 'https://media.retroachievements.org/Images/095164.png', 'https://media.retroachievements.org/Images/095165.png', 4.5),
  (43, 3706, 'Final Fight One', 'Game Boy Advance', 5, 3445, 3445, 3445, 28, 0, 'Beat ''em Up', 'Capcom', 'Capcom, Ubisoft', '2001-05-25', 'Final Fight is a 1989 beat ''em up game developed and published by Capcom for arcades. It is the seventh title released for the CP System hardware. Set in the fictional Metro City, the player controls one of three street fighters: former pro wrestler and city mayor Mike Haggar, expert brawler Cody Travers, and modern-day ninja Guy. The trio set out to rescue Jessica when she is kidnapped by the Mad Gear Gang.', 'https://media.retroachievements.org/Images/062590.png', 'https://media.retroachievements.org/Images/014474.png', 'https://media.retroachievements.org/Images/008117.png', 'https://media.retroachievements.org/Images/008118.png', 4.4),
  (44, 760, 'Drill Dozer', 'Game Boy Advance', 5, 3331, 3331, 3331, 56, 0, '2D Platforming, Action', 'Game Freak', 'Nintendo', '2006-02-06', 'Drill Dozer is a platformer video game developed by Game Freak and published by Nintendo for the Game Boy Advance (GBA). Directed by Ken Sugimori, the game stars Jill and her mech Drill Dozer, which has a drill that the player can rotate in both directions to fight enemies, drill into certain surfaces, and screw objects. Sugimori aimed to make an action game that does not use traditional types of combat, and was inspired by the concept of a tokusatsu monster who could drill through anything. He also wished to make the drill not just pushing a button, but instead using one of two buttons to activate the drill. When drilling, the built-in rumble pack will activate, a feature suggested by Nintendo.', 'https://media.retroachievements.org/Images/046590.png', 'https://media.retroachievements.org/Images/014464.png', 'https://media.retroachievements.org/Images/009457.png', 'https://media.retroachievements.org/Images/009458.png', 4.4),
  (45, 4206, 'Sword of Mana', 'Game Boy Advance', 5, 3308, 3308, 3308, 101, 0, 'Action RPG', 'Brownie Brown, Square Enix', 'Nintendo, Square Enix', '2003-12-01', 'Sword of Mana, originally released in Japan as Shin''yaku: Seiken Densetsu , is a 2003 action role-playing game developed by Square Enix and Brownie Brown and published by Square Enix and Nintendo for the Game Boy Advance. It is an enhanced remake of the first game in the Mana series, the Game Boy game Seiken Densetsu: Final Fantasy Gaiden, which was released as Final Fantasy Adventure in North America and as Mystic Quest in Europe. Sword of Mana was the fifth release in the series. Set in a high fantasy universe, the game follows an unnamed hero and heroine as they seek to defeat the Dark Lord and defend the Mana Tree from enemies who wish to misuse its power.', 'https://media.retroachievements.org/Images/123002.png', 'https://media.retroachievements.org/Images/064088.png', 'https://media.retroachievements.org/Images/008166.png', 'https://media.retroachievements.org/Images/008173.png', 4.4),
  (46, 2588, 'Summon Night: Swordcraft Story', 'Game Boy Advance', 5, 3187, 3187, 3187, 36, 0, NULL, 'Flight-Plan', 'Atlus', '2006-07-26', 'Summon Night: Swordcraft Story , is a 2003 action role-playing game developed by Flight-Plan for the Game Boy Advance. It is a spinoff of the Summon Night series of games. It was first released in Japan in April 2003, published by Banpresto. An English localized version was released in North America by Atlus in July 2006. A sequel, Summon Night: Swordcraft Story 2, was released in Japan in August 2004, and North America in October 2006.', 'https://media.retroachievements.org/Images/121536.png', 'https://media.retroachievements.org/Images/007653.png', 'https://media.retroachievements.org/Images/010288.png', 'https://media.retroachievements.org/Images/010289.png', 4.4),
  (47, 14408, '~Hack~ Pokémon FireRed: Rocket Edition', 'Game Boy Advance', 5, 3174, 3174, 3174, 42, 0, 'Turn-Based RPG', 'colonelsalt', NULL, '2020-04-09', 'Pokémon FireRed Version and Pokémon LeafGreen Version are 2004 remakes of the 1996 role-playing video games Pokémon Red and Blue. They were developed by Game Freak and published by The Pokémon Company and Nintendo for the Game Boy Advance. FireRed and LeafGreen were first released in Japan in January 2004 and in North America and Europe in September and October 2004, respectively. The games are part of the third generation of the Pokémon video game series and hold the distinction of being the first enhanced remakes of previous games within the franchise.', 'https://media.retroachievements.org/Images/122420.png', 'https://media.retroachievements.org/Images/114819.png', 'https://media.retroachievements.org/Images/033001.png', 'https://media.retroachievements.org/Images/033002.png', 4.4),
  (48, 533, 'Mario Kart: Super Circuit', 'Game Boy Advance', 5, 3107, 3107, 3107, 94, 0, 'Kart Racing', 'Intelligent Systems', 'Nintendo', '2001-08-26', 'Mario Kart: Super Circuit is a 2001 kart racing game for the Game Boy Advance (GBA). It is the third Mario Kart game and retains its predecessors'' gameplay: as a Mario franchise character, the player races opponents around tracks based on locales from the Super Mario platform games. Tracks contain obstacles and power-ups that respectively hamper and aid the player''s progress. Super Circuit includes various single-player and multiplayer game modes, including a Grand Prix racing mode and a last man standing battle mode.', 'https://media.retroachievements.org/Images/066821.png', 'https://media.retroachievements.org/Images/069295.png', 'https://media.retroachievements.org/Images/006425.png', 'https://media.retroachievements.org/Images/006426.png', 4.4),
  (49, 1416, 'Grand Theft Auto Advance', 'Game Boy Advance', 5, 3059, 3059, 3059, 41, 0, 'Action-Adventure', 'Digital Eclipse', 'Rockstar Games', '2004-10-26', 'Grand Theft Auto Advance is a 2004 action-adventure game developed by Digital Eclipse and published by Rockstar Games. The eighth entry in the Grand Theft Auto series, it was released for the Game Boy Advance in October 2004. The game takes place in Liberty City, the same setting used for Grand Theft Auto III, to which it serves as a prequel. The story, set one year before Grand Theft Auto III, follows small-time criminal Mike''s quest for revenge after his partner''s supposed death, which leads him to become entangled in a world of organised crime, gang warfare, and corruption.', 'https://media.retroachievements.org/Images/089901.png', 'https://media.retroachievements.org/Images/014480.png', 'https://media.retroachievements.org/Images/001019.png', 'https://media.retroachievements.org/Images/096539.png', 4.4),
  (50, 5255, 'Sonic Pinball Party', 'Game Boy Advance', 5, 3027, 3027, 3027, 103, 0, 'Pinball', 'Sonic Team, Jupiter', 'Sega', '2003-06-03', 'Sonic Pinball Party is a video game released for the Game Boy Advance in 2003. It is a celebration of sorts for Sonic Team featuring many references to its previous games, mostly prominently Sonic the Hedgehog, Nights into Dreams, and Samba De Amigo. There was also a release on a Twin Pack cartridge bundled with Sonic Battle and Sonic Advance respectively in 2005.', 'https://media.retroachievements.org/Images/113163.png', 'https://media.retroachievements.org/Images/071408.png', 'https://media.retroachievements.org/Images/025946.png', 'https://media.retroachievements.org/Images/033826.png', 4.4),
  (51, 5234, 'Super Mario Advance 3: Yoshi''s Island', 'Game Boy Advance', 5, 3001, 3001, 3001, 66, 0, '2D Platforming', NULL, 'Nintendo', '2002-09-20', 'Super Mario World 2: Yoshi''s Island is a 1995 platform game developed and published by Nintendo for the Super Nintendo Entertainment System (SNES). The player controls Yoshi dinosaurs on their quest to reunite baby Mario with his brother Luigi, who has been kidnapped by the wizard Kamek. Yoshi runs and jumps to reach the end of the level while solving puzzles and collecting items with Mario''s help.', 'https://media.retroachievements.org/Images/121554.png', 'https://media.retroachievements.org/Images/110912.png', 'https://media.retroachievements.org/Images/008562.png', 'https://media.retroachievements.org/Images/008561.png', 4.4),
  (52, 787, 'Naruto: Ninja Council', 'Game Boy Advance', 5, 2967, 2967, 2967, 44, 0, '2D Platforming, Beat ''em Up', 'Aspect', 'D3 Publisher, Tomy', '2006-03-07', 'The Naruto: Ninja Council series, known in Japan as Naruto: Saikyō Ninja Daikesshū , is a series of action games based on the manga and anime series Naruto by Masashi Kishimoto. They are developed by Aspect Co. and published by Tomy. Various installments of the series have appeared on both Nintendo''s Game Boy Advance and Nintendo DS, the first two games in the series available for the former while the rest are available on the latter.', 'https://media.retroachievements.org/Images/094961.png', 'https://media.retroachievements.org/Images/024187.png', 'https://media.retroachievements.org/Images/001036.png', 'https://media.retroachievements.org/Images/001037.png', 4.4),
  (53, 764, 'Final Fantasy V: Advance', 'Game Boy Advance', 5, 2947, 2947, 2947, 172, 0, NULL, 'TOSE', 'Nintendo, Square Enix', '2006-11-06', 'Final Fantasy V is a 1992 role-playing video game developed and published by Square for the Super Famicom. It is the fifth main installment of the Final Fantasy series. The game begins as a wanderer named Bartz investigates a fallen meteor. There, he encounters several characters, one of whom reveals the danger facing the four Crystals that control the world''s elements. These Crystals act as a seal on Exdeath, an evil sorcerer. Bartz and his party must keep the Crystals from being exploited by Exdeath''s influence and prevent his resurgence.', 'https://media.retroachievements.org/Images/086246.png', 'https://media.retroachievements.org/Images/069383.png', 'https://media.retroachievements.org/Images/005289.png', 'https://media.retroachievements.org/Images/005290.png', 4.4),
  (54, 5004, 'Yu-Gi-Oh! The Eternal Duelist Soul', 'Game Boy Advance', 5, 2913, 2913, 2913, 39, 0, 'Collectible Card Game', 'Konami', 'Konami', '2002-10-15', 'Yu-Gi-Oh! The Eternal Duelist Soul is a card battle video game based on the Yu-Gi-Oh! franchise. It was developed and published by Konami and released on July 5, 2001 in Japan, October 16, 2002 in the United States for Game Boy Advance. It features a single-player campaign against opponents from the Yu-Gi-Oh! anime as well as a multiplayer head-to-head mode.', 'https://media.retroachievements.org/Images/056423.png', 'https://media.retroachievements.org/Images/002796.png', 'https://media.retroachievements.org/Images/002794.png', 'https://media.retroachievements.org/Images/002795.png', 4.4),
  (55, 16209, '~Homebrew~ Celeste Classic', 'Game Boy Advance', 5, 2850, 2850, 2850, 39, 0, '2D Platforming', 'JeffRuLz', 'JeffRuLz', '2019-08-02', 'Celeste is a 2018 platform video game developed and published by indie studio Maddy Makes Games. The player controls the player character Madeline, a young woman with anxiety and depression, who endeavors to climb Celeste Mountain, a fictional version of Mount Celeste. During her climb, she encounters several characters, including a personification of her self-doubt nicknamed "Badeline", who attempts to stop her from reaching the mountain''s summit.', 'https://media.retroachievements.org/Images/088036.png', 'https://media.retroachievements.org/Images/117819.png', 'https://media.retroachievements.org/Images/115239.png', 'https://media.retroachievements.org/Images/115247.png', 4.4),
  (56, 5719, 'LEGO Star Wars: The Video Game', 'Game Boy Advance', 5, 2750, 2750, 2750, 45, 0, 'Action-Adventure', 'Griptonite Games', 'Eidos Interactive, LucasArts | Lucasfilm', '2005-03-29', 'Lego Star Wars: The Video Game is a 2005 action-adventure video game based on the line of Lego construction toys of the same name, and the first installment in the Lego video game franchise developed by Traveller''s Tales, which would develop many future Lego titles from that point on. It was first released on 29 March 2005. It is a Lego video game adaptation of the prequel trilogy of George Lucas’ movie franchise of the same name: The Phantom Menace, Attack of the Clones and Revenge of the Sith, with a bonus level from A New Hope.', 'https://media.retroachievements.org/Images/087606.png', 'https://media.retroachievements.org/Images/014489.png', 'https://media.retroachievements.org/Images/004771.png', 'https://media.retroachievements.org/Images/004772.png', 4.4),
  (57, 5127, 'Crash Nitro Kart', 'Game Boy Advance', 5, 2659, 2659, 2659, 68, 0, 'Kart Racing', 'Vicarious Visions', 'Universal Interactive', '2003-11-11', 'Crash Nitro Kart is a 2003 kart racing game developed by Vicarious Visions and published by Universal Interactive for the PlayStation 2, Xbox, and GameCube. It is the second racing game in the Crash Bandicoot series after Crash Team Racing and the first game in the series to feature full motion videos. The game''s plot centers on the abduction of Crash Bandicoot, along with other characters in the series, by the ruthless dictator Emperor Velo XXVII, who threatens to destroy the Earth if they refuse to race in his gigantic coliseum for the entertainment of his subjects.', 'https://media.retroachievements.org/Images/081321.png', 'https://media.retroachievements.org/Images/096968.png', 'https://media.retroachievements.org/Images/003368.png', 'https://media.retroachievements.org/Images/003369.png', 4.4),
  (58, 2482, 'Fire Emblem: The Sacred Stones', 'Game Boy Advance', 5, 2626, 2626, 2626, 114, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2005-11-04', 'Fire Emblem: The Sacred Stones is a tactical role-playing game developed by Intelligent Systems, and published by Nintendo for the Game Boy Advance handheld video game console in 2004 for Japan and 2005 in the West. It is the eighth entry in the Fire Emblem series, the second to be released outside Japan, and the third and final title to be developed for the Game Boy Advance after The Binding Blade and its prequel The Blazing Blade.', 'https://media.retroachievements.org/Images/102614.png', 'https://media.retroachievements.org/Images/089240.png', 'https://media.retroachievements.org/Images/012409.png', 'https://media.retroachievements.org/Images/007175.png', 4.4),
  (59, 748, 'Classic NES Series: The Legend of Zelda', 'Game Boy Advance', 5, 2601, 2601, 2601, 97, 0, 'Action-Adventure', 'Nintendo', 'Nintendo', '2004-02-14', 'The Legend of Zelda is a 1986 action-adventure game developed and published by Nintendo for the Family Computer Disk System. It is the first game in the Legend of Zelda series. It is set in the fantasy land of Hyrule and centers on an elf-like boy named Link, who aims to collect the eight fragments of the Triforce of Wisdom to rescue Princess Zelda from Ganon. The player controls Link from a top-down perspective and navigates the overworld and dungeons, collecting weapons, defeating enemies and uncovering secrets. It was designed and directed by Shigeru Miyamoto and Takashi Tezuka, being in development alongside Super Mario Bros. that released the previous year.', 'https://media.retroachievements.org/Images/060253.png', 'https://media.retroachievements.org/Images/026379.png', 'https://media.retroachievements.org/Images/088566.png', 'https://media.retroachievements.org/Images/001396.png', 4.4),
  (60, 506, 'Advance Wars', 'Game Boy Advance', 5, 2584, 2584, 2584, 92, 0, 'Turn-Based Strategy', 'Intelligent Systems', 'Nintendo', '2001-09-10', 'Advance Wars is a turn-based strategy video game developed by Intelligent Systems and published by Nintendo for the Game Boy Advance. It is the seventh title in the Wars series of video games, and the first in the Advance Wars sub-series. The game takes place on a fictional continent, where two nations, Orange Star and Blue Moon, have been fighting each other for years. The conflict enters a new stage when an Orange Star commanding officer named Andy is accused of attacking the armies of two other nations, Yellow Comet and Green Earth, without reason, resulting in a worldwide war.', 'https://media.retroachievements.org/Images/052963.png', 'https://media.retroachievements.org/Images/014431.png', 'https://media.retroachievements.org/Images/033766.png', 'https://media.retroachievements.org/Images/002529.png', 4.4),
  (61, 27584, '~Homebrew~ Goodboy Galaxy', 'Game Boy Advance', 5, 2513, 2513, 2513, 125, 0, 'Metroidvania', 'Goodboy Galaxy', 'itch.io, First Press Games', '2023-11-28', 'Goodboy Galaxy is a 2023 action-adventure game developed for the Game Boy Advance in celebration of its 20th anniversary by Rik Nicol and Jeremy Clarke. It is the first full commercial Game Boy Advance release in over 13 years. The game was also released for the PC and Evercade. Development is ongoing for the Nintendo Switch.', 'https://media.retroachievements.org/Images/086185.png', 'https://media.retroachievements.org/Images/086905.png', 'https://media.retroachievements.org/Images/086186.png', 'https://media.retroachievements.org/Images/086187.png', 4.4),
  (62, 21360, '~Hack~ Pokémon Emerald Rogue', 'Game Boy Advance', 5, 2447, 2447, 2447, 83, 0, 'Roguelike, Turn-Based RPG', 'Pokabbie', 'Hack - Pokemon Emerald Version', '2022-08-22', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/099244.png', 'https://media.retroachievements.org/Images/066833.png', 'https://media.retroachievements.org/Images/066832.png', 'https://media.retroachievements.org/Images/066831.png', 4.4),
  (63, 754, 'Dragon Ball Z: Buu''s Fury', 'Game Boy Advance', 5, 2413, 2413, 2413, 59, 0, 'Action RPG', 'Webfoot Technologies', 'Atari', '2004-09-14', 'Dragon Ball Z: The Legacy of Goku is a series of video games for the Game Boy Advance, based on the anime series Dragon Ball Z and part of the Dragon Ball video game series. All three games are action role-playing games. The first game, Dragon Ball Z: The Legacy of Goku, was developed by Webfoot Technologies and released in 2002. The game was followed by two sequels: Dragon Ball Z: The Legacy of Goku II, released in 2003, and Dragon Ball Z: Buu''s Fury, released in 2004. Buu''s Fury was re-released in 2006 as part of a Game Boy Advance two-pack, which includes Dragon Ball GT: Transformation on the same cartridge. In 2016, Webfoot Technologies claimed to be starting development of another sequel.', 'https://media.retroachievements.org/Images/094340.png', 'https://media.retroachievements.org/Images/095541.png', 'https://media.retroachievements.org/Images/003297.png', 'https://media.retroachievements.org/Images/003296.png', 4.4),
  (64, 9848, 'Action Man: Robot Atak', 'Game Boy Advance', 5, 2375, 2375, 2375, 51, 0, 'Action, 2D Platforming', 'Magic Pockets', 'Atari', '2004-09-24', 'Action Man: Robot Atak is a 2004 American animated superhero film based on the Hasbro toy line Action Man. The film was produced by Arcana Digital and directed by John Moffett, Steven Burch and Chris Woods. Released to tie-in with the line of Action Man toys released in 2004, Robot Atak was the first in a trilogy of direct-to-video films and was followed by a sequel in 2005, Action Man: X Missions - The Movie.', 'https://media.retroachievements.org/Images/048949.png', 'https://media.retroachievements.org/Images/015646.png', 'https://media.retroachievements.org/Images/082237.png', 'https://media.retroachievements.org/Images/082239.png', 4.4),
  (65, 33063, '~Hack~ Pokémon Odyssey', 'Game Boy Advance', 5, 2346, 2346, 2346, 90, 0, 'Turn-Based RPG', 'Yggdrasil Project', 'Hack - Pokemon FireRed and LeafGreen Versions', '2025-06-12', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/108871.png', 'https://media.retroachievements.org/Images/113428.png', 'https://media.retroachievements.org/Images/108876.png', 'https://media.retroachievements.org/Images/108877.png', 4.4),
  (66, 801, 'WarioWare: Twisted!', 'Game Boy Advance', 5, 2344, 2344, 2344, 50, 0, 'Minigames', 'Intelligent Systems', 'Nintendo', '2004-10-14', 'WarioWare: Twisted! is an action video game developed by Nintendo and Intelligent Systems and published by Nintendo for the Game Boy Advance. It was released on October 14, 2004 in Japan; May 19, 2005 in Australia; and May 23, 2005 in North America. The third game in the WarioWare series and the seventh in the Wario series overall, Twisted! was the last Wario game to be released on a Game Boy family system, having been released after the launch of the Nintendo DS.', 'https://media.retroachievements.org/Images/034675.png', 'https://media.retroachievements.org/Images/004477.png', 'https://media.retroachievements.org/Images/004476.png', 'https://media.retroachievements.org/Images/004499.png', 4.4),
  (67, 20277, 'Super Mario Advance 4: Super Mario Bros. 3', 'Game Boy Advance', 5, 2285, 2285, 2285, 83, 0, NULL, NULL, NULL, '2003-07-11', 'Super Mario Advance 4: Super Mario Bros. 3 is a 2003 platform game developed and published by Nintendo for the Game Boy Advance. It was released in Japan, and later released in Europe, North America, and Australia. It is an enhanced remake of the NES video game Super Mario Bros. 3, and is based on the remake found in Super Mario All-Stars for the Super Nintendo Entertainment System. Players control either Mario or Luigi as they travel through the eight kingdoms of the Mushroom World to rescue Princess Peach from Bowser. The game was revealed at Nintendo''s conference at the E3 2003 convention. It contains several enhancements, including the addition of Mario and Luigi''s voices by Charles Martinet, the ability to scan e-Cards into Nintendo''s e-Reader to add certain content, and a multiplayer mode based on the original arcade game Mario Bros.. The game also allows players to save replays of their gameplay.', 'https://media.retroachievements.org/Images/060733.png', 'https://media.retroachievements.org/Images/110841.png', 'https://media.retroachievements.org/Images/060736.png', 'https://media.retroachievements.org/Images/060735.png', 4.4),
  (68, 9957, 'The Pinball of the Dead', 'Game Boy Advance', 5, 2274, 2274, 2274, 44, 0, NULL, NULL, NULL, '2002-06-18', 'The Pinball of the Dead is a pinball video game developed by Sega''s Wow Entertainment division and published by Sega. It was released for the Game Boy Advance in 2002 and 2003. Based on Sega''s The House of the Dead series of light gun games, particularly The House of the Dead and The House of the Dead 2, the game contains three tables and includes a "Challenge" mode. Full-motion video sequences and audio samples from previous games were also added. The game was first announced during the 2001 Nintendo Space World. Composer Hitoshi Sakimoto was involved with making the game''s music.', 'https://media.retroachievements.org/Images/049625.png', 'https://media.retroachievements.org/Images/061668.png', 'https://media.retroachievements.org/Images/061666.png', 'https://media.retroachievements.org/Images/061667.png', 4.3),
  (69, 4106, 'Rayman Advance', 'Game Boy Advance', 5, 2253, 2253, 2253, 58, 0, '2D Platforming', 'Digital Eclipse', 'Ubisoft', '2001-06-11', 'Rayman is a 1995 platform game developed by Ubi Pictures and published by Ubi Soft. The player controls Rayman, who must pursue Mr Dark to recover the Great Protoon that used to keep the balance between nature and the people of Rayman''s valley. The player must navigate the valley, defeat enemies with abilities gained throughout the game, and free captured Electoons, while also encountering a boss at the end of each thematic world.', 'https://media.retroachievements.org/Images/123320.png', 'https://media.retroachievements.org/Images/123464.png', 'https://media.retroachievements.org/Images/005179.png', 'https://media.retroachievements.org/Images/005198.png', 4.3),
  (70, 2138, 'Double Dragon Advance', 'Game Boy Advance', 5, 2188, 2188, 2188, 53, 0, 'Beat ''em Up', 'Million, S-NEO, Paon', 'Atlus', '2003-11-14', 'Double Dragon Advance is a 2003 beat ''em up video game developed by Japanese studio Million and published by Atlus for the Game Boy Advance. It is a remake of Technōs Japan''s 1987 arcade game Double Dragon and incorporates elements from its sequels and home versions.', 'https://media.retroachievements.org/Images/064413.png', 'https://media.retroachievements.org/Images/014457.png', 'https://media.retroachievements.org/Images/048197.png', 'https://media.retroachievements.org/Images/082468.png', 4.3),
  (71, 529, 'Mario vs. Donkey Kong', 'Game Boy Advance', 5, 2160, 2160, 2160, 34, 0, NULL, NULL, 'Nintendo', '2004-11-19', 'Mario vs. Donkey Kong is a 2004 puzzle-platform game developed by Nintendo Software Technology and published by Nintendo for the Game Boy Advance. The game is the spiritual successor to Donkey Kong, which was released in 1994 for the Game Boy.', 'https://media.retroachievements.org/Images/024372.png', 'https://media.retroachievements.org/Images/014498.png', 'https://media.retroachievements.org/Images/001023.png', 'https://media.retroachievements.org/Images/001024.png', 4.3),
  (72, 6946, 'Bookworm', 'Game Boy Advance', 5, 2099, 2099, 2099, 57, 0, NULL, 'PopCap Games', 'Majesco Entertainment, PopCap Games', '2004-04-28', 'A bookworm or bibliophile is an individual who loves and frequently reads or collects books. Bibliophilia or bibliophilism is the love of books.', 'https://media.retroachievements.org/Images/075934.png', 'https://media.retroachievements.org/Images/019397.png', 'https://media.retroachievements.org/Images/019395.png', 'https://media.retroachievements.org/Images/019396.png', 4.3),
  (73, 5117, 'Yu-Gi-Oh! The Sacred Cards', 'Game Boy Advance', 5, 2023, 2023, 2023, 64, 0, 'Collectible Card Game', 'Konami', 'Konami', '2002-01-01', 'Yu-Gi-Oh! The Sacred Cards is a Game Boy Advance game based on the Yu-Gi-Oh! anime, developed and published by Konami. It was first released in Japan on July 4, 2002. It was released in North America the following year and in Europe the year after that.', 'https://media.retroachievements.org/Images/096892.png', 'https://media.retroachievements.org/Images/024015.png', 'https://media.retroachievements.org/Images/004534.png', 'https://media.retroachievements.org/Images/082173.png', 4.3),
  (74, 752, 'Donkey Kong Country 3', 'Game Boy Advance', 5, 1965, 1965, 1965, 27, 0, '2D Platforming', 'Rare', 'Nintendo', '2005-11-07', 'Donkey Kong Country 3: Dixie Kong''s Double Trouble!  is a 1996 platform Collectathon developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It is the third installment of the Donkey Kong Country series, and serves as a sequel to 1995''s Donkey Kong Country 2: Diddy''s Kong Quest. It was also re-released for the Game Boy Advance (GBA) in 2005. The game was made available to download on the Wii''s Virtual Console service in 2007, as well as for the Wii U''s Virtual Console in 2014.', 'https://media.retroachievements.org/Images/069873.png', 'https://media.retroachievements.org/Images/014453.png', 'https://media.retroachievements.org/Images/004275.png', 'https://media.retroachievements.org/Images/004276.png', 4.3),
  (75, 4970, 'Dr. Mario & Puzzle League', 'Game Boy Advance', 5, 1908, 1908, 1908, 63, 0, NULL, 'TOSE', 'Nintendo', '2005-11-04', 'Dr. Mario is a 1990 puzzle video game developed and published by Nintendo for the Nintendo Entertainment System and Game Boy. A spin-off of the Mario series, it is a falling block puzzle game in which the player''s objective is to destroy the viruses populating the on-screen playing field by using colored capsules that are automatically tossed into the field by Dr. Mario. The player manipulates the falling capsules, to align the same colors, which destroys viruses. The player progresses through the game by eliminating all the viruses on the screen in each level. The game was produced by Gunpei Yokoi and programmed by Takahiro Harada, with the soundtrack composed by Hirokazu Tanaka.', 'https://media.retroachievements.org/Images/060392.png', 'https://media.retroachievements.org/Images/060263.png', 'https://media.retroachievements.org/Images/060251.png', 'https://media.retroachievements.org/Images/060252.png', 4.3),
  (76, 2592, 'Golden Sun: The Lost Age', 'Game Boy Advance', 5, 1903, 1903, 1903, 97, 0, 'Turn-Based RPG', 'Camelot Software Planning', 'Nintendo', '2003-04-14', 'Golden Sun: The Lost Age is a 2002 role-playing video game for the Game Boy Advance, developed by Camelot Software Planning and published by Nintendo. It is the second installment in the Golden Sun series and was released on June 28, 2002 in Japan, and in 2003 in North America and Europe.', 'https://media.retroachievements.org/Images/059249.png', 'https://media.retroachievements.org/Images/059420.png', 'https://media.retroachievements.org/Images/006638.png', 'https://media.retroachievements.org/Images/006639.png', 4.3),
  (77, 3700, 'Who Wants to Be a Millionaire', 'Game Boy Advance', 5, 1884, 1884, 1884, 6, 0, 'Game Show', 'Hothouse Creations', 'Zoo Digital Publishing | Zushi Games', '2002-10-18', 'Who Wants to Be a Millionaire? (WWTBAM) is an international television game show franchise of British origin, created by David Briggs, Mike Whitehill and Steven Knight. In its format, currently owned and licensed by Sony Pictures Television, contestants tackle a series of multiple-choice questions to win large cash prizes in a format that twists on many game show genre conventions – only one contestant plays at a time. Similar to radio quizzes, contestants are given the question before deciding whether to answer and have no time limit to answer questions. The cash prize increases as they tackle questions that become increasingly difficult, with the maximum offered in most variants of the format being an aspirational value in the respective local currency, such as £1 million in the British version, €1 million in most European versions, $1 million in the American version and ₹75 million in the Indian version.', 'https://media.retroachievements.org/Images/071846.png', 'https://media.retroachievements.org/Images/050280.png', 'https://media.retroachievements.org/Images/050277.png', 'https://media.retroachievements.org/Images/050278.png', 4.3),
  (78, 12748, '~Prototype~ Resident Evil 2', 'Game Boy Advance', 5, 1832, 1832, 1832, 11, 0, 'Survival Horror', 'Raylight Studios', 'Capcom', NULL, 'Resident Evil 2 is a 1998 survival horror video game developed and published by Capcom for the PlayStation. It is the second main installment in the Resident Evil series. The player controls rookie cop Leon S. Kennedy and college student Claire Redfield, who must escape Raccoon City after its citizens are transformed into zombies by a biological weapon two months after the events of the original Resident Evil. The gameplay focuses on exploration, puzzles, and combat; the main difference from its predecessor are the branching paths, with each player character having unique storylines, partners and obstacles.', 'https://media.retroachievements.org/Images/101590.png', 'https://media.retroachievements.org/Images/036161.png', 'https://media.retroachievements.org/Images/101542.png', 'https://media.retroachievements.org/Images/101543.png', 4.3),
  (79, 784, 'Mega Man Zero 4', 'Game Boy Advance', 5, 1827, 1827, 1827, 52, 0, '2D Platforming, Action', 'Inti Creates', 'Capcom', '2005-04-21', 'Mega Man Zero 4 is a 2005 hack and slash platform game developed by Inti Creates and published by Capcom for the Game Boy Advance. It is the fourth and final installment of the Mega Man Zero subseries of the Mega Man franchise and is set several months after the events of Mega Man Zero 3.', 'https://media.retroachievements.org/Images/124431.png', 'https://media.retroachievements.org/Images/005028.png', 'https://media.retroachievements.org/Images/033794.png', 'https://media.retroachievements.org/Images/005210.png', 4.3),
  (80, 548, 'Naruto: Ninja Council 2', 'Game Boy Advance', 5, 1808, 1808, 1808, 23, 0, '2D Platforming, Beat ''em Up', 'Aspect, Tomy', 'D3 Publisher, Tomy', '2006-10-04', 'The Naruto: Ninja Council series, known in Japan as Naruto: Saikyō Ninja Daikesshū , is a series of action games based on the manga and anime series Naruto by Masashi Kishimoto. They are developed by Aspect Co. and published by Tomy. Various installments of the series have appeared on both Nintendo''s Game Boy Advance and Nintendo DS, the first two games in the series available for the former while the rest are available on the latter.', 'https://media.retroachievements.org/Images/055814.png', 'https://media.retroachievements.org/Images/003880.png', 'https://media.retroachievements.org/Images/001040.png', 'https://media.retroachievements.org/Images/001041.png', 4.3),
  (81, 783, 'Mega Man Zero 2', 'Game Boy Advance', 5, 1765, 1765, 1765, 45, 0, '2D Platforming, Action', 'Inti Creates', 'Capcom', '2003-10-14', 'Mega Man Zero 2 is a 2003 hack and slash platform game developed by Inti Creates and published by Capcom for the Game Boy Advance (GBA) handheld game console. It is the second video game in the Mega Man Zero subseries of Mega Man video games.', 'https://media.retroachievements.org/Images/124432.png', 'https://media.retroachievements.org/Images/003326.png', 'https://media.retroachievements.org/Images/033795.png', 'https://media.retroachievements.org/Images/004953.png', 4.3),
  (82, 6643, '~Hack~ Pokémon Ultra Violet Version', 'Game Boy Advance', 5, 1734, 1734, 1734, 29, 0, 'Turn-Based RPG', 'LocksmithArmy', NULL, '2013-07-02', 'The third generation (generation III) of the Pokémon franchise features 386 fictional species of creatures and 135 Pokémon introduced to the core video game series in the 2002 Game Boy Advance games Pokémon Ruby and Sapphire, and later in the 2004 game Pokémon Emerald. These games were accompanied by the television series Pokémon Advanced, which aired from November 21, 2002, until August 28, 2003, in Japan.', 'https://media.retroachievements.org/Images/042470.png', 'https://media.retroachievements.org/Images/008888.png', 'https://media.retroachievements.org/Images/008625.png', 'https://media.retroachievements.org/Images/008627.png', 4.3),
  (83, 5245, '~Hack~ Pokémon AshGray Version', 'Game Boy Advance', 5, 1720, 1720, 1720, 139, 0, 'Turn-Based RPG', 'Metapod23', NULL, '2015-03-03', 'The Nintendo Switch is a video game console developed by Nintendo and released worldwide in most regions on March 3, 2017. Released in the middle of the eighth generation of home consoles, the Switch succeeded the Wii U and competed with Sony''s PlayStation 4 and Microsoft''s Xbox One; it also competes with the ninth-generation consoles, the PlayStation 5 and Xbox Series X/S.', 'https://media.retroachievements.org/Images/090474.png', 'https://media.retroachievements.org/Images/007953.png', 'https://media.retroachievements.org/Images/025681.png', 'https://media.retroachievements.org/Images/008763.png', 4.3),
  (84, 4703, 'Shining Soul', 'Game Boy Advance', 5, 1716, 1716, 1716, 63, 0, 'Action RPG', 'Nex Entertainment, Grasshopper Manufacture', 'Sega, Atlus', '2002-03-28', 'Shining Soul is an action role-playing game for the Game Boy Advance. It is part of the Shining series. Shining Soul is a reboot of the Shining series. The game was followed by a sequel, Shining Soul II, in 2003. Both games were re-released in Japan in early 2006 as part of the Game Boy Advance "Value Selection".', 'https://media.retroachievements.org/Images/074707.png', 'https://media.retroachievements.org/Images/014901.png', 'https://media.retroachievements.org/Images/014902.png', 'https://media.retroachievements.org/Images/014900.png', 4.3),
  (85, 5520, 'Pac-Man Collection', 'Game Boy Advance', 5, 1678, 1678, 1678, 71, 0, NULL, 'Mass Media', 'Namco', '2001-07-12', 'Pac-Man Collection is a 2001 video game compilation developed by Mass Media and published by Namco for the Game Boy Advance. It includes four titles in the Pac-Man series — the original Pac-Man (1980), Pac-Mania (1987), Pac-Attack (1993), and Pac-Man Arrangement (1996), the latter of which was originally exclusive to the arcade game Namco Classic Collection Vol. 2. Each game includes customizable features such as the ability to alter the number of starting lives or difficulty, with all being stripped of multiplayer features.', 'https://media.retroachievements.org/Images/065959.png', 'https://media.retroachievements.org/Images/066664.png', 'https://media.retroachievements.org/Images/008234.png', 'https://media.retroachievements.org/Images/008233.png', 4.3),
  (86, 5987, 'Hamtaro: Ham-Ham Heartbreak', 'Game Boy Advance', 5, 1649, 1649, 1649, 35, 0, 'Action', 'Pax Softnica', 'Nintendo', '2003-04-08', 'Hamtaro: Ham-Ham Heartbreak is a video game in the Hamtaro game series for Game Boy Advance developed by Pax Softnica and published by Nintendo, as the sequel to Tottoko Hamutaro: Tomodachi Daisakusen Dechu and Hamtaro: Ham-Hams Unite!. It was the second Hamtaro game released in America and Europe, but the third released in Japan. It was released in Japan on May 3, 2002, in North America on April 7, 2003, in Australia on May 30, 2003, and in Europe on June 27, 2003. Hamtaro: Ham-Ham Heartbreak was followed by Hamtaro: Rainbow Rescue.', 'https://media.retroachievements.org/Images/059649.png', 'https://media.retroachievements.org/Images/009537.png', 'https://media.retroachievements.org/Images/033783.png', 'https://media.retroachievements.org/Images/009546.png', 4.3),
  (87, 5080, 'Tim Burton''s The Nightmare Before Christmas: The Pumpkin King', 'Game Boy Advance', 5, 1643, 1643, 1643, 71, 0, 'Metroidvania', 'TOSE', 'Buena Vista Games, D3 Publisher', '2005-09-08', 'Tim Burton''s The Nightmare Before Christmas: The Pumpkin King is a 2005 platform game developed by Tose for the Game Boy Advance. The game was published by D3 Publisher in Japan, and by Buena Vista Games internationally. A prequel to the 1993 stop motion animated film The Nightmare Before Christmas, it tells the story of Jack Skellington''s first encounter with Oogie Boogie, and how he claimed the title of "The Pumpkin King".', 'https://media.retroachievements.org/Images/046730.png', 'https://media.retroachievements.org/Images/014426.png', 'https://media.retroachievements.org/Images/003207.png', 'https://media.retroachievements.org/Images/003212.png', 4.3),
  (88, 4879, 'Fire Emblem: Fuuin no Tsurugi', 'Game Boy Advance', 5, 1637, 1637, 1637, 70, 0, 'Tactical RPG', 'Intelligent Systems', 'Nintendo', '2002-03-29', 'Fire Emblem: The Binding Blade is a 2002 tactical role-playing game developed by Intelligent Systems and published by Nintendo for the Game Boy Advance (GBA). It is the sixth entry in the Fire Emblem series, the first title produced for the system, and the first title to appear on a handheld console.', 'https://media.retroachievements.org/Images/076394.png', 'https://media.retroachievements.org/Images/014475.png', 'https://media.retroachievements.org/Images/006218.png', 'https://media.retroachievements.org/Images/006220.png', 4.3),
  (89, 8701, 'Classic NES Series: Castlevania', 'Game Boy Advance', 5, 1635, 1635, 1635, 26, 0, '2D Platforming', 'Konami', 'Nintendo', '2004-08-10', 'Castlevania, known in Japan as Akumajō Dracula, is a 1986 platform game developed and published by Konami. It was originally released in Japan for the Famicom Disk System in September 1986, before being ported to cartridge format and released in North America for the Nintendo Entertainment System (NES) in 1987 and in Europe in 1988. It was also re-issued for the Family Computer in cartridge format in 1993. It is the first installment in the Castlevania series.', 'https://media.retroachievements.org/Images/112767.png', 'https://media.retroachievements.org/Images/072394.png', 'https://media.retroachievements.org/Images/060254.png', 'https://media.retroachievements.org/Images/060255.png', 4.3),
  (90, 532, 'Mario Golf: Advance Tour', 'Game Boy Advance', 5, 1614, 1614, 1614, 70, 0, 'Sports - Golf, Role-Playing Game', 'Camelot Software Planning', 'Nintendo', '2004-06-22', 'Mario Golf: Advance Tour is a 2004 sports role-playing video game developed by Camelot Software Planning and published by Nintendo for the Game Boy Advance. The game is the sequel to the Game Boy Color version of Mario Golf and the Game Boy Advance counterpart of Mario Golf: Toadstool Tour.', 'https://media.retroachievements.org/Images/029865.png', 'https://media.retroachievements.org/Images/071183.png', 'https://media.retroachievements.org/Images/033787.png', 'https://media.retroachievements.org/Images/003638.png', 4.3),
  (91, 7128, 'Elf: The Movie', 'Game Boy Advance', 5, 1604, 1604, 1604, 19, 0, 'Action Adventure', 'Jolliford Management Limited', 'Crave Entertainment', '2004-01-01', 'Elf is a 2003 American Christmas comedy film directed by Jon Favreau and written by David Berenbaum. It stars Will Ferrell as Buddy the Elf, a human raised by Santa''s elves, who learns about his origins and heads to New York City to meet his biological father. James Caan, Zooey Deschanel, Mary Steenburgen, Ed Asner and Bob Newhart appear in supporting roles.', 'https://media.retroachievements.org/Images/049698.png', 'https://media.retroachievements.org/Images/006760.png', 'https://media.retroachievements.org/Images/006759.png', 'https://media.retroachievements.org/Images/006763.png', 4.3),
  (92, 572, 'Magical Quest 3 Starring Mickey & Donald', 'Game Boy Advance', 5, 1525, 1525, 1525, 57, 0, '2D Platforming', 'Capcom', 'Capcom', '2005-06-14', 'Disney''s Magical Quest is a Disney platform game trilogy released by Capcom. The games star Mickey Mouse and either Minnie Mouse or Donald Duck, who must defeat Pete. The gameplay is similar amongst all games in the series: the player must move as in a typical platform game, defeating enemies either by jumping on them or by grabbing and throwing blocks at them.', 'https://media.retroachievements.org/Images/108392.png', 'https://media.retroachievements.org/Images/014449.png', 'https://media.retroachievements.org/Images/008357.png', 'https://media.retroachievements.org/Images/008356.png', 4.3),
  (93, 5312, 'The King of Fighters EX2: Howling Blood', 'Game Boy Advance', 5, 1523, 1523, 1523, 46, 0, '2D Fighting', 'Marvelous Interactive', 'Atlus, Acclaim, Marvelous Interactive', '2003-12-11', 'The King of Fighters EX 2 Howling Blood is a fighting game developed by Marvelous Entertainment for Nintendo''s Game Boy Advance. It is a spin-off of SNK''s The King of Fighters series and acts as a sequel to The King of Fighters EX: Neo Blood. Despite taking graphics, characters and audio from The King of Fighters 2000, the game features an original storyline that focuses on Kyo Kusanagi and his allies in stopping the revival of the demon Yamata no Orochi from Heavenly Kings. It was announced for a 2003 release in the same console. The game was also ported to the N-Gage under the name The King of Fighters Extreme. Hudson Soft developed the game, and it was published by Nokia in Europe.', 'https://media.retroachievements.org/Images/079760.png', 'https://media.retroachievements.org/Images/007124.png', 'https://media.retroachievements.org/Images/007121.png', 'https://media.retroachievements.org/Images/118218.png', 4.3),
  (94, 625, 'Mega Man Zero 3', 'Game Boy Advance', 5, 1514, 1514, 1514, 53, 0, '2D Platforming, Action', 'Inti Creates', 'Capcom', '2004-10-05', 'Mega Man Zero 3 is a 2004 hack and slash platform game developed by Inti Creates and published by Capcom for the Game Boy Advance (GBA) handheld game console. It is the third video game in the Mega Man Zero series of Mega Man video games. The European version featured a completely different logo, which was also used on various other Mega Man titles.', 'https://media.retroachievements.org/Images/042926.png', 'https://media.retroachievements.org/Images/039503.png', 'https://media.retroachievements.org/Images/033796.png', 'https://media.retroachievements.org/Images/039504.png', 4.3),
  (95, 2412, 'Yu-Gi-Oh! Worldwide Edition: Stairway to the Destined Duel', 'Game Boy Advance', 5, 1514, 1514, 1514, 79, 0, NULL, 'Konami', 'Konami', '2003-04-15', 'Yu-Gi-Oh! Worldwide Edition: Stairway to the Destined Duel, later released in Japan as Yu-Gi-Oh! Duel Monsters International , is a Game Boy Advance game developed and published by Konami in 2003. It is a modified version of Yu-Gi-Oh! Duel Monsters 6 Expert 2, previously released for the Game Boy Advance in 2001, and adapts the "Battle City" story arc of the original Yu-Gi-Oh! series. The game was re-released in 2025 as part of the Yu-Gi-Oh! Early Days Collection game compilation.', 'https://media.retroachievements.org/Images/057886.png', 'https://media.retroachievements.org/Images/024090.png', 'https://media.retroachievements.org/Images/008895.png', 'https://media.retroachievements.org/Images/008896.png', 4.3),
  (96, 509, 'Bomberman Tournament', 'Game Boy Advance', 5, 1499, 1499, 1499, 56, 0, 'Action RPG', 'Hudson Soft', 'Activision', '2001-04-27', 'Bomberman Tournament is a game in the Bomberman series for the Game Boy Advance. The game contains a multiplayer battle mode between linked Game Boy Advance consoles. The player and up to three others can compete in any of the game''s eight multiplayer battle arenas, each of which has its own unique gameplay twist.', 'https://media.retroachievements.org/Images/052576.png', 'https://media.retroachievements.org/Images/003285.png', 'https://media.retroachievements.org/Images/002717.png', 'https://media.retroachievements.org/Images/002718.png', 4.3),
  (97, 18985, '~Hack~ Pokémon Sword and Shield Ultimate Plus', 'Game Boy Advance', 5, 1496, 1496, 1496, 102, 0, NULL, 'PCL.G, Jeanstars & Phantonomy', NULL, '2024-10-18', 'The third generation (generation III) of the Pokémon franchise features 386 fictional species of creatures and 135 Pokémon introduced to the core video game series in the 2002 Game Boy Advance games Pokémon Ruby and Sapphire, and later in the 2004 game Pokémon Emerald. These games were accompanied by the television series Pokémon Advanced, which aired from November 21, 2002, until August 28, 2003, in Japan.', 'https://media.retroachievements.org/Images/104747.png', 'https://media.retroachievements.org/Images/101735.png', 'https://media.retroachievements.org/Images/101739.png', 'https://media.retroachievements.org/Images/101740.png', 4.2),
  (98, 4201, 'Harry Potter and the Sorcerer''s Stone', 'Game Boy Advance', 5, 1480, 1480, 1480, 34, 0, 'Action-Adventure', 'Griptonite Games', 'Electronic Arts', '2001-11-15', 'Harry Potter and the Philosopher''s Stone is a fantasy novel by British author J. K. Rowling. It is the first novel in the Harry Potter series and was Rowling''s debut novel. It follows Harry Potter, a young wizard who discovers his magical heritage on his eleventh birthday when he receives a letter of acceptance from Hogwarts School of Witchcraft and Wizardry. With the help of his friends, Ron Weasley and Hermione Granger, Harry unravels a mystery involving the dark wizard Lord Voldemort.', 'https://media.retroachievements.org/Images/124569.png', 'https://media.retroachievements.org/Images/020817.png', 'https://media.retroachievements.org/Images/020816.png', 'https://media.retroachievements.org/Images/020818.png', 4.2),
  (99, 2543, 'Konami Krazy Racers', 'Game Boy Advance', 5, 1472, 1472, 1472, 68, 0, 'Kart Racing', 'KCEK', 'Konami', '2001-03-21', 'Konami Krazy Racers is a 2001 kart-themed racing video game developed and published by Konami for the Game Boy Advance. Released as a launch title for the system, Konami Krazy Racers makes use of a variety of characters and concepts from several of Konami''s franchises, including Castlevania, Metal Gear, and Gradius. It plays similarly to the Mario Kart series, with eight characters per circuit and offensive/defensive items placed at predetermined points in the tracks. Konami Krazy Racers received mostly positive reviews. It was later released through the Virtual Console for the Wii U in 2015.', 'https://media.retroachievements.org/Images/107129.png', 'https://media.retroachievements.org/Images/065794.png', 'https://media.retroachievements.org/Images/014313.png', 'https://media.retroachievements.org/Images/014314.png', 4.2),
  (100, 4872, 'Breath of Fire', 'Game Boy Advance', 5, 1470, 1470, 1470, 68, 0, 'Turn-Based RPG', 'Capcom', 'Capcom', '2001-12-31', 'Breath of Fire is a role-playing video game series developed by Capcom. It originated on the Super Nintendo Entertainment System in 1993. The series has recurring characters and ambiguous continuity; though each game is its own self-contained story, the names of the two lead characters are usually Ryu and Nina.', 'https://media.retroachievements.org/Images/104995.png', 'https://media.retroachievements.org/Images/033806.png', 'https://media.retroachievements.org/Images/044276.png', 'https://media.retroachievements.org/Images/044275.png', 4.2),
  (101, 4964, '~Hack~ Pokémon Liquid Crystal Version', 'Game Boy Advance', 5, 1457, 1457, 1457, 74, 0, 'Turn-Based RPG', 'Linkandzelda, Zeikku', NULL, '2007-04-01', 'The Game Boy Advance SP is a 32-bit handheld game console made by Nintendo. It was released in Japan on February 14, 2003, and in international markets in March. The SP is an upgraded version of the Game Boy Advance with a more compact clamshell design.', 'https://media.retroachievements.org/Images/110367.png', 'https://media.retroachievements.org/Images/044490.png', 'https://media.retroachievements.org/Images/009132.png', 'https://media.retroachievements.org/Images/009131.png', 4.2),
  (102, 4853, 'Harvest Moon: Friends of Mineral Town', 'Game Boy Advance', 5, 1455, 1455, 1455, 150, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '2003-04-18', 'Harvest Moon: Friends of Mineral Town is a video game for the Game Boy Advance, developed and published by Marvelous Interactive. It is the first Game Boy Advance game of the Story of Seasons series, and is a remake of Harvest Moon: Back to Nature. It was first released in Japan in April 2003, in North America in November 2003, and in Europe in March 2004. Many critics praised it as the best entry of the series, combining elements from the best-selling console entries and introducing many notable series staples. It was later released on the Virtual Console for the Wii U in June 2015.', 'https://media.retroachievements.org/Images/120932.png', 'https://media.retroachievements.org/Images/006281.png', 'https://media.retroachievements.org/Images/006279.png', 'https://media.retroachievements.org/Images/006280.png', 4.2),
  (103, 6184, 'The Sims: Bustin'' Out', 'Game Boy Advance', 5, 1442, 1442, 1442, 50, 0, 'Life Simulation', 'Griptonite Games', 'Electronic Arts', '2003-12-02', 'The Sims Bustin'' Out is a 2003 social simulation video game developed by Maxis and published by Electronic Arts for the Game Boy Advance, GameCube, PlayStation 2 and Xbox, with a port for the N-Gage following in 2004. It is the second title in The Sims console series, and the first title not to be concurrently released for Microsoft Windows.', 'https://media.retroachievements.org/Images/066855.png', 'https://media.retroachievements.org/Images/008305.png', 'https://media.retroachievements.org/Images/066854.png', 'https://media.retroachievements.org/Images/008967.png', 4.2),
  (104, 763, 'Final Fantasy IV: Advance', 'Game Boy Advance', 5, 1440, 1440, 1440, 95, 0, NULL, 'TOSE', 'Nintendo', '2005-12-12', 'Final Fantasy IV, titled Final Fantasy II in its initial North American release, is a 1991 role-playing video game developed and published by Square for the Super Nintendo Entertainment System. It is the fourth main installment of the Final Fantasy series. The game''s story follows Cecil Harvey, a dark knight, as he tries to prevent the sorcerer Golbez from seizing powerful crystals and destroying the world. He is joined on this quest by a frequently changing group of allies. Final Fantasy IV introduced innovations that became staples of the Final Fantasy series and role-playing games in general. Its "Active Time Battle" system was used in five subsequent Final Fantasy games, and unlike prior games in the series, Final Fantasy IV gave each character their own unchangeable character class — although at a few points in the story, members of the cast change or evolve their vocation to suit the narrative.', 'https://media.retroachievements.org/Images/070792.png', 'https://media.retroachievements.org/Images/014471.png', 'https://media.retroachievements.org/Images/033778.png', 'https://media.retroachievements.org/Images/002914.png', 4.2),
  (105, 766, 'Game & Watch Gallery 4', 'Game Boy Advance', 5, 1439, 1439, 1439, 67, 0, 'Compilation', 'TOSE', 'Nintendo', '2002-10-28', 'Game & Watch Gallery 4, known as Game & Watch Gallery Advance in Europe and Australia and Game Boy Gallery 4 in Japan, is a video game developed by Tose and published by Nintendo for the Game Boy Advance in October 2002. It is the fifth and final game in the Game & Watch Gallery series, and contains 11 remastered games from the Game & Watch line of Nintendo handheld games, several of which were featured in previous series entries.', 'https://media.retroachievements.org/Images/113333.png', 'https://media.retroachievements.org/Images/014477.png', 'https://media.retroachievements.org/Images/007152.png', 'https://media.retroachievements.org/Images/007153.png', 4.2),
  (106, 7274, 'Pac-Man Pinball Advance', 'Game Boy Advance', 5, 1429, 1429, 1429, 37, 0, 'Pinball', 'Human Soft', 'Namco, Zoo Digital Publishing | Zushi Games', '2005-05-02', 'Pac-Man Pinball Advance is a pinball video game developed by Hungarian studio Human Soft and published by Namco Hometek for the Game Boy Advance. It was released in North America on May 3, 2005. It is part of the Pac-Man video game franchise.', 'https://media.retroachievements.org/Images/122950.png', 'https://media.retroachievements.org/Images/007110.png', 'https://media.retroachievements.org/Images/007111.png', 'https://media.retroachievements.org/Images/007112.png', 4.2),
  (107, 4203, 'Spyro: Season of Ice', 'Game Boy Advance', 5, 1406, 1406, 1406, 35, 0, '2.5D Platforming', 'Digital Eclipse', 'Universal Interactive', '2001-10-29', 'Spyro: Season of Ice is a 2001 platform game developed by Digital Eclipse and published by Universal Interactive Studios for the Game Boy Advance. It acts as an alternate sequel to the first three games along with Spyro 2: Season of Flame and Spyro: Attack of the Rhynocs.', 'https://media.retroachievements.org/Images/071269.png', 'https://media.retroachievements.org/Images/006568.png', 'https://media.retroachievements.org/Images/006566.png', 'https://media.retroachievements.org/Images/006567.png', 4.2),
  (108, 4200, 'Harry Potter and the Prisoner of Azkaban', 'Game Boy Advance', 5, 1402, 1402, 1402, 54, 0, 'Role-Playing', 'Griptonite Games', 'Electronic Arts', '2004-05-25', 'Harry Potter and the Prisoner of Azkaban is a fantasy novel by British author J. K. Rowling. The third novel in the Harry Potter series, it follows the young wizard Harry Potter during his third year at Hogwarts School of Witchcraft and Wizardry. With his friends Ron Weasley and Hermione Granger, Harry investigates Sirius Black, an escaped prisoner who is believed to be one of Lord Voldemort''s allies.', 'https://media.retroachievements.org/Images/023013.png', 'https://media.retroachievements.org/Images/020819.png', 'https://media.retroachievements.org/Images/020820.png', 'https://media.retroachievements.org/Images/020821.png', 4.2),
  (109, 5093, 'Mario Party Advance', 'Game Boy Advance', 5, 1402, 1402, 1402, 63, 0, 'Board Game, Minigames', 'Hudson Soft', 'Nintendo', '2005-01-13', 'Mario Party Advance is a 2005 party video game developed by Hudson Soft and published by Nintendo for the Game Boy Advance. It is the first handheld game in the Mario Party series and the seventh entry in the series overall. The game was released in Japan on January 13, 2005, North America on March 28, 2005, Europe on June 10, 2005, and Australia on September 15, 2005. The game was re-released on the Virtual Console for the Wii U in 2014.', 'https://media.retroachievements.org/Images/087672.png', 'https://media.retroachievements.org/Images/111786.png', 'https://media.retroachievements.org/Images/003219.png', 'https://media.retroachievements.org/Images/003220.png', 4.2),
  (110, 2598, 'One Piece', 'Game Boy Advance', 5, 1389, 1389, 1389, 38, 0, '2D Platforming, Action-Adventure', 'Dimps', 'Bandai', '2005-09-07', 'One Piece is a Japanese manga series written and illustrated by Eiichiro Oda. It follows the adventures of Monkey D. Luffy and his crew, the Straw Hat Pirates, as he explores the Grand Line in search of the mythical treasure known as the "One Piece" to become the next King of the Pirates.', 'https://media.retroachievements.org/Images/121444.png', 'https://media.retroachievements.org/Images/001581.png', 'https://media.retroachievements.org/Images/001578.png', 'https://media.retroachievements.org/Images/001579.png', 4.2),
  (111, 527, 'Shaman King: Master of Spirits', 'Game Boy Advance', 5, 1372, 1372, 1372, 66, 0, 'Metroidvania', 'Konami', 'Konami', '2004-11-09', 'Shaman King: Master of Spirits is a Metroidvania video game developed by Konami Computer Entertainment Japan and published by Konami. This is the first Shaman King game that was developed for the Game Boy Advance in America. It was developed to accompany the English dub by 4kids Entertainment.', 'https://media.retroachievements.org/Images/114103.png', 'https://media.retroachievements.org/Images/083763.png', 'https://media.retroachievements.org/Images/033749.png', 'https://media.retroachievements.org/Images/003330.png', 4.2),
  (112, 5030, 'Digimon Battle Spirit', 'Game Boy Advance', 5, 1365, 1365, 1365, 34, 0, 'Platform Fighting', 'Dimps', 'Bandai', '2003-01-13', 'Digimon Battle Spirit is a fighting video game originally published by Bandai and developed by Dimps for the Japanese-only WonderSwan Color handheld system under the name Digimon Tamers: Battle Spirit . It was later ported to Nintendo''s Game Boy Advance for international releases in North America and Europe two years later.', 'https://media.retroachievements.org/Images/104143.png', 'https://media.retroachievements.org/Images/026233.png', 'https://media.retroachievements.org/Images/026234.png', 'https://media.retroachievements.org/Images/026236.png', 4.2),
  (113, 5057, 'The Urbz: Sims in the City', 'Game Boy Advance', 5, 1353, 1353, 1353, 90, 0, 'Life Simulation', 'Griptonite Games', 'Electronic Arts', '2004-11-09', 'The Urbz: Sims in the City is a 2004 life simulation video game developed by Maxis and published by Electronic Arts for the Game Boy Advance, GameCube, PlayStation 2, Xbox, and Nintendo DS. It is the third Sims game for consoles, and the second not to be released for Microsoft Windows, after a planned PC port and sequel were both cancelled due to mediocre sales. The next release for consoles and handhelds was the console port of The Sims 2.', 'https://media.retroachievements.org/Images/036497.png', 'https://media.retroachievements.org/Images/015773.png', 'https://media.retroachievements.org/Images/015771.png', 'https://media.retroachievements.org/Images/015772.png', 4.2),
  (114, 2531, 'Doom II', 'Game Boy Advance', 5, 1337, 1337, 1337, 52, 0, 'First-Person Shooter', 'Torus Games', 'Activision', '2002-10-28', 'Doom II, also known as Doom II: Hell on Earth, is a 1994 first-person shooter game developed and published by id Software for MS-DOS. It was also released on Mac OS the following year. Unlike the original Doom, which was initially only available through shareware and mail order, Doom II was sold in stores, making it the first game in the Doom franchise to be released initially in stores.', 'https://media.retroachievements.org/Images/053767.png', 'https://media.retroachievements.org/Images/014456.png', 'https://media.retroachievements.org/Images/009168.png', 'https://media.retroachievements.org/Images/009169.png', 4.2),
  (115, 2179, 'Mega Man & Bass', 'Game Boy Advance', 5, 1318, 1318, 1318, 74, 0, '2D Platforming', 'Capcom', 'Capcom', '2002-08-10', 'Mega Man & Bass is a 1998 action game developed and published by Capcom. It is a spin-off game in the original Mega Man series, and was originally released in Japan for the Super Famicom on April 24, 1998. It was later ported to the Game Boy Advance in 2002, and released internationally the following year.', 'https://media.retroachievements.org/Images/028134.png', 'https://media.retroachievements.org/Images/000849.png', 'https://media.retroachievements.org/Images/122428.png', 'https://media.retroachievements.org/Images/122429.png', 4.2),
  (116, 5114, 'Yu-Gi-Oh! World Championship Tournament 2004', 'Game Boy Advance', 5, 1302, 1302, 1302, 80, 0, 'Strategy–Trading Card Game', 'Konami', 'Konami', '2004-02-10', 'Yu-Gi-Oh! World Championship Tournament 2004, known in Japan as Yu-Gi-Oh! Duel Monsters Expert 3, is a card battle video game based on the Yu-Gi-Oh! franchise. This game was released for the Game Boy Advance system in 2004, and was re-released in 2025 as part of the Yu-Gi-Oh! Early Days Collection game compilation.', 'https://media.retroachievements.org/Images/103758.png', 'https://media.retroachievements.org/Images/003300.png', 'https://media.retroachievements.org/Images/003303.png', 'https://media.retroachievements.org/Images/003304.png', 4.2),
  (117, 7159, 'The Polar Express', 'Game Boy Advance', 5, 1294, 1294, 1294, 24, 0, 'Action-Adventure', 'Tantalus Interactive', 'THQ', '2004-01-01', 'The Polar Express is a 1985 fantasy children''s picture book written and illustrated by American author Chris Van Allsburg. The book is now widely considered to be a classic Christmas story for young children. It was praised for its detailed illustrations and calm, relaxing storyline. For the work, Van Allsburg won the annual Caldecott Medal for illustration of an American children''s picture book in 1986, his second after Jumanji.', 'https://media.retroachievements.org/Images/105604.png', 'https://media.retroachievements.org/Images/077245.png', 'https://media.retroachievements.org/Images/006878.png', 'https://media.retroachievements.org/Images/006879.png', 4.2),
  (118, 3681, 'Lady Sia', 'Game Boy Advance', 5, 1278, 1278, 1278, 57, 0, '2D Platforming', 'RFX Interactive', 'TDK Mediactive', '2001-10-16', 'Lady Sia is a platform game with action-adventure elements made by RFX Interactive for the Game Boy Advance. It was published by TDK Mediactive, released in the USA on October 15, 2001, and released in Europe on October 19, 2001. Lady Sia is one of the few original games produced by RFX Interactive. The game takes place in a fantasy world where the player assumes the role of the She-Ra/Xena-esque warrior princess, Lady Sia. It is her task to defeat the T''soas, a race of creatures created by the evil warlock Onimen who has declared war on the other realms. Her quest leads her through four different realms, the last one being the home continent of the T''soas themselves. A sequel was planned for the GameCube and GBA in 2003 but was cancelled due to TDK Mediactive being purchased by Take-Two Interactive that same year.', 'https://media.retroachievements.org/Images/083613.png', 'https://media.retroachievements.org/Images/096226.png', 'https://media.retroachievements.org/Images/019009.png', 'https://media.retroachievements.org/Images/019010.png', 4.2),
  (119, 503, 'Tetris Worlds', 'Game Boy Advance', 5, 1246, 1246, 1246, 35, 0, NULL, '3d6 Games', 'THQ', '2001-09-05', 'Tetris Worlds is a version of the video game Tetris. Originally released in 2001 for Microsoft Windows and Game Boy Advance, it was later released for Xbox, GameCube, and PlayStation 2 in 2002. In 2003, an Xbox Live version titled Tetris Worlds Online and a single-disc compilation version were released for the Xbox. The latter was bundled with Xbox systems.', 'https://media.retroachievements.org/Images/109837.png', 'https://media.retroachievements.org/Images/007462.png', 'https://media.retroachievements.org/Images/026407.png', 'https://media.retroachievements.org/Images/026408.png', 4.2),
  (120, 18464, 'Classic NES Series: Metroid', 'Game Boy Advance', 5, 1236, 1236, 1236, 34, 0, '2D Platforming, Metroidvania', 'Nintendo', 'Nintendo', '2004-08-10', 'Metroid is a 1986 action-adventure game developed and published by Nintendo. The first installment in the Metroid series, it was originally released in Japan for the Family Computer Disk System in August 1986. North America received a release in August 1987 on the Nintendo Entertainment System, with the European release following in January 1988. Set on the planet Zebes, the story follows Samus Aran as she attempts to retrieve the predatory Metroid organisms that were stolen by Space Pirates, who plan to replicate the Metroids by exposing them to beta rays and then use them as biological weapons to destroy Samus and all who oppose them.', 'https://media.retroachievements.org/Images/079410.png', 'https://media.retroachievements.org/Images/096967.png', 'https://media.retroachievements.org/Images/052655.png', 'https://media.retroachievements.org/Images/052656.png', 4.2),
  (121, 3653, 'Klonoa: Empire of Dreams', 'Game Boy Advance', 5, 1216, 1216, 1216, 15, 0, '2D Platforming', 'Now Production', 'Infogrames, Namco', '2001-07-19', 'Klonoa: Empire of Dreams is a 2001 puzzle-platform game published by Namco for the Game Boy Advance. Falling somewhere between Klonoa: Door to Phantomile and Klonoa 2: Lunatea''s Veil, Empire of Dreams takes place in the new realm in the Klonoa series, the Empire of Jillius.', 'https://media.retroachievements.org/Images/077323.png', 'https://media.retroachievements.org/Images/014485.png', 'https://media.retroachievements.org/Images/033786.png', 'https://media.retroachievements.org/Images/004462.png', 4.2),
  (122, 3618, 'Crash Bandicoot Purple: Ripto''s Rampage', 'Game Boy Advance', 5, 1179, 1179, 1179, 57, 0, '2D Platforming, Minigames', 'Vicarious Visions', 'Vivendi Universal Games', '2004-06-03', 'Crash Bandicoot Purple: Ripto''s Rampage and Spyro Orange: The Cortex Conspiracy are two 2004 action games developed by Vicarious Visions and published by Vivendi Universal Games for the Game Boy Advance. The games are a crossover between the Crash Bandicoot and Spyro series, and are the fourth installments of each series made for the GBA. The story follows Crash Bandicoot and Spyro the Dragon as they team up and set out to thwart the alliance of their respective enemies Doctor Neo Cortex and Ripto. In a departure from the series'' usual format, the gameplay of both titles is based heavily on minigames.', 'https://media.retroachievements.org/Images/040178.png', 'https://media.retroachievements.org/Images/014442.png', 'https://media.retroachievements.org/Images/005803.png', 'https://media.retroachievements.org/Images/005811.png', 4.2),
  (123, 6818, 'Sonic the Hedgehog: Genesis', 'Game Boy Advance', 5, 1169, 1169, 1169, 25, 0, '2D Platforming', 'Sega', 'Sega', '2006-11-14', 'Sonic the Hedgehog is a Japanese video game series and media franchise created by the Japanese developers Yuji Naka, Naoto Ohshima, and Hirokazu Yasuhara for Sega. The franchise follows Sonic, an anthropomorphic blue hedgehog with supersonic speed, who battles the mad scientist Doctor Eggman and his robot army. The main Sonic the Hedgehog games are platformers mostly developed by Sonic Team; other games, developed by various studios, include spin-offs in the racing, fighting, party and sports genres. The franchise also incorporates printed media, animations, films, and merchandise.', 'https://media.retroachievements.org/Images/071905.png', 'https://media.retroachievements.org/Images/015209.png', 'https://media.retroachievements.org/Images/015207.png', 'https://media.retroachievements.org/Images/015208.png', 4.2),
  (124, 22659, '~Homebrew~ Sips', 'Game Boy Advance', 5, 1129, 1129, 1129, 10, 0, 'Incremental', 'Jono Shields', 'Jono Shields', '2023-02-22', 'SİPER (Trench) is a high to medium air defense surface-to-air missile (SAM) system. Designed to defend against any type of airborne threat, it can engage aircraft, cruise missiles, air-to-ground missiles and unmanned aerial vehicles (UAVs). It was jointly developed in Turkey by the companies Roketsan, Aselsan and the research institute TÜBİTAK SAGE.', 'https://media.retroachievements.org/Images/121562.png', 'https://media.retroachievements.org/Images/087377.png', 'https://media.retroachievements.org/Images/068857.png', 'https://media.retroachievements.org/Images/068858.png', 4.2),
  (125, 2595, 'Mother 1+2', 'Game Boy Advance', 5, 1111, 1111, 1111, 181, 0, 'Compilation, Turn-Based RPG', 'APE | Creatures, HAL Laboratory', 'Nintendo', '2003-06-20', 'Mother is a video game series that consists of three role-playing video games: Mother (1989), known as EarthBound Beginnings outside Japan, for the Family Computer; Mother 2 (1994), known as EarthBound outside Japan, for the Super Nintendo Entertainment System; and Mother 3 (2006) for the Game Boy Advance.', 'https://media.retroachievements.org/Images/121262.png', 'https://media.retroachievements.org/Images/022816.png', 'https://media.retroachievements.org/Images/022817.png', 'https://media.retroachievements.org/Images/022818.png', 4.2),
  (126, 26278, 'Who Wants to Be a Millionaire: Junior', 'Game Boy Advance', 5, 1103, 1103, 1103, 7, 0, 'Game Show, Trivia', 'Hothouse Creations', 'Zoo Digital Publishing | Zushi Games', '2005-09-30', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/083705.png', 'https://media.retroachievements.org/Images/083700.png', 'https://media.retroachievements.org/Images/083701.png', 'https://media.retroachievements.org/Images/083704.png', 4.2),
  (127, 5501, 'SpongeBob SquarePants: SuperSponge', 'Game Boy Advance', 5, 1070, 1070, 1070, 12, 0, '2D Platforming', 'Climax Studios', 'THQ', '2001-11-08', 'SpongeBob SquarePants: SuperSponge is a 2001 platform game based on the Nickelodeon animated television series SpongeBob SquarePants. Developed by Climax Development and published by THQ, it was released for the PlayStation on September 20, 2001, and for the Game Boy Advance on November 8, 2001.', 'https://media.retroachievements.org/Images/071506.png', 'https://media.retroachievements.org/Images/014370.png', 'https://media.retroachievements.org/Images/123183.png', 'https://media.retroachievements.org/Images/123184.png', 4.2),
  (128, 6011, 'Mr. Driller 2', 'Game Boy Advance', 5, 1069, 1069, 1069, 42, 0, 'Puzzle', 'Namco', 'Namco', '2001-03-21', 'Mr. Driller 2 is a 2000 puzzle video game developed and published by Namco for arcades. It is the second game in the Mr. Driller series, and was later ported to the Game Boy Advance and Windows in 2001 and 2002. The game introduces two new characters to the series, Puchi, and Anna.', 'https://media.retroachievements.org/Images/088319.png', 'https://media.retroachievements.org/Images/014610.png', 'https://media.retroachievements.org/Images/033747.png', 'https://media.retroachievements.org/Images/022013.png', 4.2),
  (129, 2585, 'Super Street Fighter II Turbo Revival', 'Game Boy Advance', 5, 1060, 1060, 1060, 36, 0, '2D Fighting', 'Capcom', 'Capcom', '2001-10-30', 'Super Street Fighter II Turbo, released in Japan as Super Street Fighter II X: Grand Master Challenge, is a 1994 fighting game developed and published by Capcom for arcades. It is the fifth installment in the Street Fighter II sub-series of Street Fighter games, following Super Street Fighter II (1993). Like its predecessor, it ran on the CP System II hardware.', 'https://media.retroachievements.org/Images/104583.png', 'https://media.retroachievements.org/Images/014335.png', 'https://media.retroachievements.org/Images/001564.png', 'https://media.retroachievements.org/Images/001565.png', 4.2),
  (130, 4690, 'Iridion 3D', 'Game Boy Advance', 5, 1039, 1039, 1039, 32, 0, 'Rail Shooter', 'Shin''en Multimedia', 'Majesco Entertainment', '2001-05-29', 'Iridion 3D is a quasi-3D rail shooter video game developed by Shin''en Multimedia. A launch title for the Game Boy Advance portable game console, it was released in North America on June 11, 2001 and in Europe on September 21. The player controls a single starship defending Earth from the alien Iridion. The game spans seven levels from Earth to the aliens'' home planet, each following a linear path that culminate with a boss.', 'https://media.retroachievements.org/Images/032753.png', 'https://media.retroachievements.org/Images/008658.png', 'https://media.retroachievements.org/Images/008655.png', 'https://media.retroachievements.org/Images/008656.png', 4.2),
  (131, 6161, 'Scurge: Hive', 'Game Boy Advance', 5, 1018, 1018, 1018, 46, 0, 'Metroidvania', 'Orbital Media', 'SouthPeak Interactive', '2006-10-31', 'Scurge: Hive is an action-adventure video game by Orbital Media released for the Game Boy Advance and Nintendo DS in 2006. The game follows the protagonist Jenosa Arma, a bounty huntress tasked with hunting a parasitic lifeform called the "Scurge" an alien entity capable of rapidly adapting to and infecting biological, mechanical, and digital systems, including the player. Throughout the game, Jenosa Arma will have to battle various forms of the Scurge virus and race against the clock as the parasite slowly takes over Jenosa''s body. The gameplay takes place in an isometric perspective.', 'https://media.retroachievements.org/Images/042512.png', 'https://media.retroachievements.org/Images/098498.png', 'https://media.retroachievements.org/Images/033753.png', 'https://media.retroachievements.org/Images/040297.png', 4.2),
  (132, 29025, '~Homebrew~ Apotris', 'Game Boy Advance', 5, 1011, 1011, 1011, 53, 0, NULL, 'Apostolos Kouzoukos', 'Apostolos Kouzoukos', '2022-05-04', NULL, 'https://media.retroachievements.org/Images/099287.png', 'https://media.retroachievements.org/Images/096180.png', 'https://media.retroachievements.org/Images/096719.png', 'https://media.retroachievements.org/Images/096720.png', 4.2),
  (133, 5441, 'Baldur''s Gate: Dark Alliance', 'Game Boy Advance', 5, 987, 987, 987, 39, 0, 'Action RPG, Hack & Slash', 'Magic Pockets', 'Destination Software', '2004-02-10', 'Baldur''s Gate: Dark Alliance is a 2001 action role-playing video game developed by Snowblind Studios and published by Interplay Entertainment subsidiary Black Isle Studios for the PlayStation 2 and the Xbox consoles, with High Voltage Software handling the GameCube port and Magic Pockets developing the Game Boy Advance version. CD Projekt was developing a version for Microsoft Windows, which was ultimately cancelled.', 'https://media.retroachievements.org/Images/114463.png', 'https://media.retroachievements.org/Images/008029.png', 'https://media.retroachievements.org/Images/124751.png', 'https://media.retroachievements.org/Images/124752.png', 4.2),
  (134, 22834, '~Hack~ Castlevania: Aria of Sorrow Reprise', 'Game Boy Advance', 5, 985, 985, 985, 49, 0, NULL, 'Xanthus', NULL, '2023-02-19', 'Castlevania is a video game series created and published by Konami. The series debuted in Japan on September 26, 1986, with Akumajō Dracula , which was later released as Castlevania in the United States and PAL. Titles in the series have been released on numerous video game consoles, handheld game consoles, and personal computer platforms, and several have been re-released on multiple platforms and included as part of compilation packages.', 'https://media.retroachievements.org/Images/117260.png', 'https://media.retroachievements.org/Images/087378.png', 'https://media.retroachievements.org/Images/069434.png', 'https://media.retroachievements.org/Images/069435.png', 4.2),
  (135, 7854, 'X-Men: Reign of Apocalypse', 'Game Boy Advance', 5, 959, 959, 959, 32, 0, 'Beat ''em Up', 'Digital Eclipse', 'Activision', '2001-09-25', 'X-Men: Reign of Apocalypse is a 2001 beat ''em up game developed by Digital Eclipse and published by Activision for the Game Boy Advance. Players control the X-Men as they attempt to find the missing Professor X and stop Apocalypse from devastating the world.', 'https://media.retroachievements.org/Images/084491.png', 'https://media.retroachievements.org/Images/008179.png', 'https://media.retroachievements.org/Images/008182.png', 'https://media.retroachievements.org/Images/008180.png', 4.1),
  (136, 2155, 'TMNT', 'Game Boy Advance', 5, 957, 957, 957, 38, 0, NULL, 'Ubisoft Montreal', 'Ubisoft', '2007-03-20', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/116863.png', 'https://media.retroachievements.org/Images/049479.png', 'https://media.retroachievements.org/Images/008688.png', 'https://media.retroachievements.org/Images/008689.png', 4.1),
  (137, 9595, '~Hack~ Pokémon Adventure: Red Chapter', 'Game Boy Advance', 5, 954, 954, 954, 134, 0, 'Turn-Based RPG', 'Aethestode', NULL, '2019-01-30', '  This is a list of video game franchises, organized alphabetically. All entries include multiple video games, not counting ports or altered re-releases.', 'https://media.retroachievements.org/Images/123771.png', 'https://media.retroachievements.org/Images/026042.png', 'https://media.retroachievements.org/Images/026044.png', 'https://media.retroachievements.org/Images/026043.png', 4.1),
  (138, 17561, '~Hack~ Samus Goes to the Fridge to Get a Glass of Milk', 'Game Boy Advance', 5, 954, 954, 954, 7, 0, NULL, 'Hacker - kkzero', 'Hack - Metroid Fusion', '2020-03-02', NULL, 'https://media.retroachievements.org/Images/045271.png', 'https://media.retroachievements.org/Images/043089.png', 'https://media.retroachievements.org/Images/043085.png', 'https://media.retroachievements.org/Images/043086.png', 4.1),
  (139, 6663, 'Star Wars - Episode III: Revenge of the Sith', 'Game Boy Advance', 5, 953, 953, 953, 73, 0, 'Action, Adventure', 'Ubisoft', 'Ubisoft', '2005-05-04', 'Star Wars: Episode III – Revenge of the Sith is an action video game based on the 2005 film of the same name. It was released on May 5, 2005, for the PlayStation 2, Xbox, Game Boy Advance, Nintendo DS, and Symbian OS. For the Xbox 360''s backwards compatible lineup, Revenge of the Sith is one out of the 400+ backwards compatible games for the 360. As part of the PlayStation 2 classics program, the PlayStation 2 version was re-released in Europe on the PlayStation Network on February 11, 2015, and in North America on April 28, 2015 for PlayStation 3. Meanwhile, the Xbox version was also added to the backwards compatibility list for the Xbox One and Xbox Series X/S on November 15, 2021. A PlayStation Portable version was in development, but was cancelled. It received mixed reviews from critics.', 'https://media.retroachievements.org/Images/044088.png', 'https://media.retroachievements.org/Images/007981.png', 'https://media.retroachievements.org/Images/044102.png', 'https://media.retroachievements.org/Images/044101.png', 4.1),
  (140, 5179, 'Sigma Star Saga', 'Game Boy Advance', 5, 920, 920, 920, 89, 0, NULL, 'WayForward', 'Namco', '2005-08-16', 'Sigma Star Saga is a 2005 hybrid science fiction role-playing-space-shooter developed by WayForward Technologies and published by Namco Hometek for the Game Boy Advance. The player explores a standard 2-D overworld, but is transported into space for side-scrolling shooter random battles. The story focus on a space pilot named Ian Recker who goes undercover against Earth''s enemies, the Krill, in a battle to save the planet.', 'https://media.retroachievements.org/Images/076983.png', 'https://media.retroachievements.org/Images/009652.png', 'https://media.retroachievements.org/Images/009654.png', 'https://media.retroachievements.org/Images/009655.png', 4.1),
  (141, 29837, 'Who Wants to Be a Millionaire: 2nd Edition', 'Game Boy Advance', 5, 913, 913, 913, 7, 0, 'Game Show, Trivia', 'Hothouse Creations', 'Zoo Digital Publishing | Zushi Games', '2004-10-15', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/097735.png', 'https://media.retroachievements.org/Images/097548.png', 'https://media.retroachievements.org/Images/097550.png', 'https://media.retroachievements.org/Images/097549.png', 4.1),
  (142, 796, 'Spyro 2: Season of Flame', 'Game Boy Advance', 5, 904, 904, 904, 46, 0, '2.5D Platforming', 'Digital Eclipse', 'Universal Interactive', '2002-09-25', 'Spyro 2: Season of Flame is a 2002 platform game developed by Digital Eclipse and published by Universal Interactive for the Game Boy Advance. It is the fifth installment in the Spyro video game series and a sequel to Spyro: Season of Ice. The game''s story centers on the abduction of the Dragon Realm''s fireflies at the hands of the Rhynocs, causing the dragons to lose their ability to breathe fire. The protagonist of the story, Spyro the Dragon, must recover the fireflies and uncover the culprit behind the firefly theft.', 'https://media.retroachievements.org/Images/071270.png', 'https://media.retroachievements.org/Images/040526.png', 'https://media.retroachievements.org/Images/004307.png', 'https://media.retroachievements.org/Images/004311.png', 4.1),
  (143, 8010, '~Homebrew~ Flappy Bird', 'Game Boy Advance', 5, 861, 861, 861, 11, 0, 'Endless Runner', 'Jay Van Hutten', 'Jay Van Hutten', '2014-12-29', 'Flappy Bird is a 2013 casual mobile game developed by Vietnamese video game artist and programmer Dong Nguyen, under his game development company .Gears. The game is a side-scroller where the player controls a bird, Faby, attempting to fly between columns of green pipes without hitting them. The player''s score is determined by the number of pipes they pass. Nguyen created the game over a period of several days, using the bird from a cancelled game made in 2012.', 'https://media.retroachievements.org/Images/043921.png', 'https://media.retroachievements.org/Images/044597.png', 'https://media.retroachievements.org/Images/043917.png', 'https://media.retroachievements.org/Images/043918.png', 4.1),
  (144, 5119, 'Tokyo Xtreme Racer Advance', 'Game Boy Advance', 5, 837, 837, 837, 41, 0, 'Arcade Racing', 'David A. Palmer Productions', 'Crave Entertainment', '2005-04-20', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/095550.png', 'https://media.retroachievements.org/Images/053479.png', 'https://media.retroachievements.org/Images/053477.png', 'https://media.retroachievements.org/Images/053482.png', 4.1),
  (145, 29874, '~Demo~ WarioWare, Inc.: Trial Version', 'Game Boy Advance', 5, 811, 811, 811, 8, 0, 'Minigames', 'Nintendo', 'Nintendo', '2003-05-30', 'WarioWare: Touched! is a 2004 action game developed by Nintendo SPD and Intelligent Systems and published by Nintendo for the Nintendo DS. The fourth installment of the WarioWare series, and the first of three on the Nintendo DS, the game involves rapidly completing "microgames" — simple minigames lasting extremely short periods of time — as quickly as possible. The microgames are exclusively controlled with the Nintendo DS''s touchscreen and microphone.', 'https://media.retroachievements.org/Images/098061.png', 'https://media.retroachievements.org/Images/098114.png', 'https://media.retroachievements.org/Images/098072.png', 'https://media.retroachievements.org/Images/098073.png', 4.1),
  (146, 2509, 'River City Ransom EX', 'Game Boy Advance', 5, 811, 811, 811, 49, 0, 'Beat ''em Up', 'Million', 'Atlus', '2004-05-26', 'Downtown Nekketsu Monogatari, released as River City Ransom in North America and Street Gangs in PAL regions, is a 1989 action-adventure beat ''em up video game developed and published by Technōs Japan for the Nintendo Entertainment System. It is the third installment of the Kunio-kun series released for the NES, preceded by Renegade and Super Dodge Ball, and the first to be developed specifically for the system.', 'https://media.retroachievements.org/Images/054766.png', 'https://media.retroachievements.org/Images/008717.png', 'https://media.retroachievements.org/Images/002772.png', 'https://media.retroachievements.org/Images/017130.png', 4.1),
  (147, 2540, 'The Simpsons: Road Rage', 'Game Boy Advance', 5, 808, 808, 808, 36, 0, 'Arcade Racing', 'Radical Entertainment, Fox Interactive, Altron', 'Electronic Arts, THQ', '2001-11-24', 'The Simpsons: Road Rage is a 2001 racing video game based on the animated television series The Simpsons, and is part of a series of games based on the show. It was released for PlayStation 2, Xbox and GameCube. A Game Boy Advance version was released in 2003.', 'https://media.retroachievements.org/Images/120850.png', 'https://media.retroachievements.org/Images/016112.png', 'https://media.retroachievements.org/Images/016110.png', 'https://media.retroachievements.org/Images/016111.png', 4.1),
  (148, 5491, 'Digimon Battle Spirit 2', 'Game Boy Advance', 5, 805, 805, 805, 45, 0, 'Platform Fighting', 'Dimps', 'Bandai', '2003-09-24', 'Digimon Battle Spirit 2 is a fighting video game released for WonderSwan Color in 2002 and Game Boy Advance in 2004. It was developed by Dimps and published by Bandai based on the fourth season of the Digimon anime, Digimon Frontier. It was originally released in Japan for the WonderSwan Color handheld in December 2002 with the title Digimon Frontier: Battle Spirit . It was later ported to the Game Boy Advance for the Western market, released in North America in September 2003, and Europe in August 2004.', 'https://media.retroachievements.org/Images/104474.png', 'https://media.retroachievements.org/Images/026240.png', 'https://media.retroachievements.org/Images/026237.png', 'https://media.retroachievements.org/Images/026239.png', 4.1),
  (149, 2506, 'Teenage Mutant Ninja Turtles', 'Game Boy Advance', 5, 800, 800, 800, 29, 0, NULL, 'Konami', 'Konami', '2003-10-31', 'Teenage Mutant Ninja Turtles (TMNT) is an American media franchise created by comic book artists Kevin Eastman and Peter Laird. It follows Leonardo, Donatello, Raphael and Michelangelo, four anthropomorphic turtle brothers trained in ninjutsu who fight evil in New York City. The franchise encompasses printed media, television series, feature films, video games, and merchandise.', 'https://media.retroachievements.org/Images/104018.png', 'https://media.retroachievements.org/Images/007567.png', 'https://media.retroachievements.org/Images/007578.png', 'https://media.retroachievements.org/Images/007580.png', 4.1),
  (150, 5284, 'Spider-Man', 'Game Boy Advance', 5, 799, 799, 799, 40, 0, 'Action', 'Digital Eclipse Software', 'Activision', '2002-04-16', 'Spider-Man is a superhero in American comic books published by Marvel Comics. Created by writer-editor Stan Lee and artist Steve Ditko, he first appeared in the anthology comic book Amazing Fantasy #15 in the Silver Age of Comic Books. Widely regarded as one of the most popular and commercially successful superheroes, he has been featured in comic books, television shows, films, video games, novels, and plays.', 'https://media.retroachievements.org/Images/034056.png', 'https://media.retroachievements.org/Images/023488.png', 'https://media.retroachievements.org/Images/023489.png', 'https://media.retroachievements.org/Images/023490.png', 4.1),
  (151, 4723, 'Medabots: Metabee Version', 'Game Boy Advance', 5, 797, 797, 797, 36, 0, 'Role-Playing Game', 'Natsume', 'Natsume', '2003-03-31', 'Medabots, known in Japan as Medarot , is a Japanese role-playing video game franchise created by Rin Horuma (Horumarin) and currently owned by Imagineer. The main series of RPGs focus on collecting and battling with the titular robots. The bulk of the games releases have been on Nintendo platforms, including the Game Boy, GameCube, and the DS, and 3DS handhelds.', 'https://media.retroachievements.org/Images/041429.png', 'https://media.retroachievements.org/Images/002555.png', 'https://media.retroachievements.org/Images/003171.png', 'https://media.retroachievements.org/Images/003176.png', 4.1),
  (152, 7095, 'Shining Soul II', 'Game Boy Advance', 5, 791, 791, 791, 52, 0, 'Action RPG', 'Grasshopper Manufacture, Nex Entertainment', 'Atlus', '2004-04-20', 'Shining Soul II is an action role-playing game for the Game Boy Advance. It was developed by Grasshopper Manufacture, as the sequel to Shining Soul and part of the Shining series. The game was originally scheduled to be released on February 24, 2004, before it was delayed by two months.', 'https://media.retroachievements.org/Images/046731.png', 'https://media.retroachievements.org/Images/014903.png', 'https://media.retroachievements.org/Images/007244.png', 'https://media.retroachievements.org/Images/007245.png', 4.1),
  (153, 7202, 'The Lord of the Rings: The Two Towers', 'Game Boy Advance', 5, 781, 781, 781, 44, 0, 'Action RPG', 'Griptonite Games', 'Electronic Arts', '2002-11-08', 'The Lord of the Rings: The Two Towers is a 2002 epic fantasy film directed by Peter Jackson from a screenplay by Fran Walsh, Philippa Boyens, Stephen Sinclair, and Jackson, based on 1954''s The Two Towers, the second volume of the novel The Lord of the Rings by J. R. R. Tolkien. The sequel to 2001''s The Lord of the Rings: The Fellowship of the Ring, the film is the second instalment in The Lord of the Rings trilogy. It features an ensemble cast including Elijah Wood, Ian McKellen, Liv Tyler, Viggo Mortensen, Sean Astin, Cate Blanchett, John Rhys-Davies, Bernard Hill, Christopher Lee, Billy Boyd, Dominic Monaghan, Orlando Bloom, Hugo Weaving, Miranda Otto, David Wenham, Brad Dourif, Karl Urban, and Andy Serkis. Continuing the plot of the previous film, it intercuts three storylines: Frodo and Sam continue their journey toward Mordor to destroy the One Ring, now allied with Gollum, the ring''s untrustworthy former bearer. Merry and Pippin escape their orc captors, meet Treebeard the Ent, and help to plan an attack on Isengard, the fortress of Sauron''s vassal, the treacherous wizard Saruman. Aragorn, Legolas, and Gimli come to the war-torn nation of Rohan and are reunited with the resurrected Gandalf, before joining king Théoden to fight Saruman''s army at the Battle of Helm''s Deep.', 'https://media.retroachievements.org/Images/084114.png', 'https://media.retroachievements.org/Images/020850.png', 'https://media.retroachievements.org/Images/020848.png', 'https://media.retroachievements.org/Images/042091.png', 4.1),
  (154, 535, 'Super Puzzle Fighter II Turbo', 'Game Boy Advance', 5, 778, 778, 778, 25, 0, NULL, 'Capcom', 'Capcom', '2003-03-31', 'Super Puzzle Fighter II Turbo, released in Japan as Super Puzzle Fighter II X, is a 1996 tile-matching puzzle video game developed and published by Capcom for arcades. The game''s title is a play on Super Street Fighter II Turbo, as there were no other Puzzle Fighter games at the time, and the game includes music and interface elements spoofing the Street Fighter Alpha and Darkstalkers games. It was a response to Compile and Sega''s Puyo Puyo 2 that had been sweeping the Japanese arcade scene.', 'https://media.retroachievements.org/Images/123106.png', 'https://media.retroachievements.org/Images/001563.png', 'https://media.retroachievements.org/Images/033742.png', 'https://media.retroachievements.org/Images/001561.png', 4.1),
  (155, 4204, 'Spyro: Attack of the Rhynocs', 'Game Boy Advance', 5, 775, 775, 775, 64, 0, '2.5D Platforming, Collect-a-thon, Metroidvania', 'Digital Eclipse', 'Universal Interactive', '2003-10-28', 'Spyro: Attack of the Rhynocs is a 2003 platform game developed by Digital Eclipse and published by Universal Interactive for the Game Boy Advance. It was the last Spyro game to be released under the Universal Interactive label, which would be phased out shortly after the game''s release. It was also the final Spyro game to be developed by Digital Eclipse, who would be replaced for the next major handheld entries by Amaze Entertainment.', 'https://media.retroachievements.org/Images/071271.png', 'https://media.retroachievements.org/Images/049129.png', 'https://media.retroachievements.org/Images/008115.png', 'https://media.retroachievements.org/Images/009550.png', 4.1),
  (156, 8677, 'Classic NES Series: Donkey Kong', 'Game Boy Advance', 5, 774, 774, 774, 20, 0, '2D Platforming, Arcade', 'Nintendo', 'Nintendo', '2004-02-14', 'Donkey Kong Country, known in Japan as Super Donkey Kong, is a 1994 platform game developed by Rare and published by Nintendo for the Super Nintendo Entertainment System (SNES). It follows the gorilla Donkey Kong and his nephew Diddy Kong as they set out to recover their stolen banana hoard from the crocodile King K. Rool and his army, the Kremlings. The player traverses 40 side-scrolling levels as they jump between platforms and avoid obstacles. They collect items, ride minecarts and animals, defeat enemies and bosses, and find secret bonus stages. In multiplayer modes, two players work cooperatively or race.', 'https://media.retroachievements.org/Images/115153.png', 'https://media.retroachievements.org/Images/042606.png', 'https://media.retroachievements.org/Images/042603.png', 'https://media.retroachievements.org/Images/042604.png', 4.1),
  (157, 8915, 'Dora the Explorer: Dora''s World Adventure', 'Game Boy Advance', 5, 764, 764, 764, 19, 0, 'Adventure, Educational', 'Black Lantern Studios', 'Global Star Software', '2006-10-02', 'Game Boy Advance Video was a format for putting full color, full-motion videos onto Game Boy Advance ROM cartridges. These videos are playable using the Game Boy Advance system''s screen and sound hardware. They were all published by Majesco Entertainment, except for the Pokémon Game Boy Advance Video cartridges, which were published by Nintendo. Most cartridges were developed by DC Studios, Inc., except for the few labelled "Movie Pak" which were developed by 4Kids Entertainment''s subsidiary 4Kids Technology, Inc. The video cartridges are colored white for easy identification and are sold as Game Boy Advance Video Paks; these offer the same 240×160 resolution as standard Game Boy Advance games, except for the Shrek and Shark Tale pack, which is at 112p.', 'https://media.retroachievements.org/Images/115972.png', 'https://media.retroachievements.org/Images/016947.png', 'https://media.retroachievements.org/Images/084412.png', 'https://media.retroachievements.org/Images/084413.png', 4.1),
  (158, 5910, 'The Incredibles', 'Game Boy Advance', 5, 762, 762, 762, 21, 0, 'Beat ''em Up', 'Helixe', 'THQ', '2004-09-28', 'The Incredibles is a 2004 American animated superhero film written and directed by Brad Bird. Produced by Pixar Animation Studios for Walt Disney Pictures, it stars the voices of Craig T. Nelson, Holly Hunter, Sarah Vowell, Spencer Fox, Jason Lee, Samuel L. Jackson, and Elizabeth Peña. Set in a retro-futuristic version of the 1960s, the film follows Bob (Nelson) and Helen Parr (Hunter), a superhero couple respectively known as Mr. Incredible and Elastigirl, who hide their powers in accordance with a government mandate that outlawed superheroes, and attempt to live a quiet suburban life with their three children. However, Bob''s desire to help people draws the entire family into a confrontation with a vengeful fan-turned-foe.', 'https://media.retroachievements.org/Images/071603.png', 'https://media.retroachievements.org/Images/057804.png', 'https://media.retroachievements.org/Images/057802.png', 'https://media.retroachievements.org/Images/057803.png', 4.1),
  (159, 12963, '3 Game Pack!: The Game of Life + Payday + Yahtzee', 'Game Boy Advance', 5, 755, 755, 755, 25, 0, 'Board Game', 'Black Lantern Studios', 'Destination Software', '2005-11-07', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/060096.png', 'https://media.retroachievements.org/Images/018160.png', 'https://media.retroachievements.org/Images/018161.png', 'https://media.retroachievements.org/Images/018162.png', 4.1),
  (160, 773, 'Mega Man Battle Network 2', 'Game Boy Advance', 5, 751, 751, 751, 80, 0, 'Action RPG', 'Capcom', 'Capcom', '2002-06-17', 'Mega Man Battle Network 2 is a 2001 tactical role-playing game developed by Capcom for the Game Boy Advance (GBA) handheld game console. It is the second game in the Mega Man Battle Network series, and a sequel to the first game; it follows Lan Hikari and his NetNavi MegaMan.EXE as they attempt to take down the new NetCrime syndicate Gospel.', 'https://media.retroachievements.org/Images/086570.png', 'https://media.retroachievements.org/Images/039574.png', 'https://media.retroachievements.org/Images/033799.png', 'https://media.retroachievements.org/Images/039575.png', 4.1),
  (161, 3701, 'Duke Nukem Advance', 'Game Boy Advance', 5, 747, 747, 747, 62, 0, 'First-Person Shooter', 'Torus Games', 'Take-Two Interactive', '2002-08-12', 'Duke Nukem Advance is a 2002 video game in the Duke Nukem series, released for the Game Boy Advance. Although it is a first-person shooter and many of the graphics and sounds have been ported from Duke Nukem 3D, the game has an original storyline and levels, and can thus be considered to be a spin-off of 3D.', 'https://media.retroachievements.org/Images/092793.png', 'https://media.retroachievements.org/Images/014465.png', 'https://media.retroachievements.org/Images/004271.png', 'https://media.retroachievements.org/Images/004272.png', 4.1),
  (162, 5116, 'Yu-Gi-Oh! 7 Trials to Glory: World Championship Tournament 2005', 'Game Boy Advance', 5, 740, 740, 740, 40, 0, 'Collectible Card Game', 'Konami', 'Konami', '2004-12-30', '   The following is a list of video games developed and published by Konami, based on Kazuki Takahashi''s Yu-Gi-Oh! manga and anime franchise, along with its spin-off series. With some exceptions, the majority of the games follow the card battle gameplay of the real-life Yu-Gi-Oh! Trading Card Game. There are 59 in total.', 'https://media.retroachievements.org/Images/061105.png', 'https://media.retroachievements.org/Images/108534.png', 'https://media.retroachievements.org/Images/007218.png', 'https://media.retroachievements.org/Images/007270.png', 4.1),
  (163, 1420, 'Super Ghouls ''n Ghosts', 'Game Boy Advance', 5, 737, 737, 737, 60, 0, NULL, 'Capcom', 'Capcom', '2002-09-23', 'Super Ghouls ''n Ghosts, known as Chō Makaimura in Japan, is a 1991 platform video game developed and published by Capcom for the Super Nintendo Entertainment System. The third installment in the Ghosts ''n Goblins series and the first not to be released for arcades, it again depicts knight Arthur saving Princess Guinevere and the kingdom from Emperor Sardius, who has cast a spell that has revived the Ghoul Realm.', 'https://media.retroachievements.org/Images/052636.png', 'https://media.retroachievements.org/Images/017207.png', 'https://media.retroachievements.org/Images/048223.png', 'https://media.retroachievements.org/Images/048226.png', 4.1),
  (164, 9226, 'Wolfenstein 3D', 'Game Boy Advance', 5, 721, 721, 721, 28, 0, 'First-Person Shooter', 'id Software', 'BAM! Entertainment', '2002-04-02', 'Wolfenstein 3D is a 1992 first-person shooter game developed by id Software and published by Apogee Software and FormGen for MS-DOS. It was inspired by the 1981 Muse Software video game Castle Wolfenstein, and is the third installment in the Wolfenstein series. In Wolfenstein 3D, the player assumes the role of Allied spy William "B.J." Blazkowicz during World War II as he escapes from the Nazi German prison Castle Wolfenstein and carries out a series of crucial missions against the Nazis. The player traverses each of the game''s levels to find an elevator to the next level or kill a final boss, fighting Nazi soldiers, dogs, and other enemies with a knife and a variety of guns.', 'https://media.retroachievements.org/Images/064379.png', 'https://media.retroachievements.org/Images/094843.png', 'https://media.retroachievements.org/Images/094844.png', 'https://media.retroachievements.org/Images/094842.png', 4.1),
  (165, 4197, 'Harry Potter and the Chamber of Secrets', 'Game Boy Advance', 5, 709, 709, 709, 30, 0, 'Action, Adventure', 'Eurocom', 'Electronic Arts', '2002-11-14', 'Harry Potter and the Chamber of Secrets is a fantasy novel by British author J. K. Rowling. The second novel in the Harry Potter series, it chronicles Harry Potter''s second year at Hogwarts School of Witchcraft and Wizardry. After several residents of the school are attacked and magically immobilised, Harry and his friends Ron and Hermione investigate.', 'https://media.retroachievements.org/Images/114342.png', 'https://media.retroachievements.org/Images/020807.png', 'https://media.retroachievements.org/Images/020814.png', 'https://media.retroachievements.org/Images/020815.png', 4.1),
  (166, 6209, 'Guilty Gear X Advance Edition', 'Game Boy Advance', 5, 703, 703, 703, 54, 0, '2D Fighting', 'Arc System Works', 'Sammy', '2002-08-29', 'Guilty Gear X, subtitled By Your Side in Japan, is a fighting game developed by Arc System Works and published by Sammy Studios. The second installment of the Guilty Gear series, Guilty Gear X was developed over a period of about two years after the first game''s success. It was released in July 2000 for Japanese arcades, re-released on Dreamcast in December 2000, and later ported to PlayStation 2 in November 2001 and Game Boy Advance in January 2002.', 'https://media.retroachievements.org/Images/070045.png', 'https://media.retroachievements.org/Images/007277.png', 'https://media.retroachievements.org/Images/007278.png', 'https://media.retroachievements.org/Images/007280.png', 4.1),
  (167, 5764, '~Hack~ Castlevania: Aria of Sorrow Alter', 'Game Boy Advance', 5, 699, 699, 699, 64, 0, 'Metroidvania', 'Kseptuple', NULL, '2019-03-31', 'Castlevania: Circle of the Moon, titled Castlevania in PAL regions, is a 2001 action role-playing game developed and published by Konami for the Game Boy Advance handheld game console. The game was developed as a stand-alone title in the Castlevania series and as a launch title for the Game Boy Advance.', 'https://media.retroachievements.org/Images/024703.png', 'https://media.retroachievements.org/Images/024702.png', 'https://media.retroachievements.org/Images/024700.png', 'https://media.retroachievements.org/Images/024701.png', 4.1),
  (168, 6407, 'Nicktoons: Battle for Volcano Island', 'Game Boy Advance', 5, 675, 675, 675, 16, 0, '2D Platforming', 'Halfbrick Studios', 'THQ', '2006-01-01', 'Nicktoons: Battle for Volcano Island is an action-adventure video game developed by Blue Tongue Entertainment, Halfbrick (GBA), Natsume (DS), published by THQ, and it is the sequel to the 2005 video game Nicktoons Unite!. The game was first released on October 24, 2006.', 'https://media.retroachievements.org/Images/121939.png', 'https://media.retroachievements.org/Images/014597.png', 'https://media.retroachievements.org/Images/122154.png', 'https://media.retroachievements.org/Images/014595.png', 4.1),
  (169, 4092, 'Shaman King: Master of Spirits 2', 'Game Boy Advance', 5, 666, 666, 666, 55, 0, 'Metroidvania', 'KCEJ', 'Konami', '2005-08-02', 'Shaman King: Master of Spirits 2 is the sequel to the Game Boy Advance game Shaman King: Master of Spirits that had been released in 2004. Konami decided to make a sequel to this game, released on August 2, 2005, in the United States and Europe.', 'https://media.retroachievements.org/Images/114112.png', 'https://media.retroachievements.org/Images/003345.png', 'https://media.retroachievements.org/Images/003343.png', 'https://media.retroachievements.org/Images/003344.png', 4.1),
  (170, 6289, 'Donald Duck Advance!', 'Game Boy Advance', 5, 657, 657, 657, 30, 0, '2D Platforming', 'Disney Interactive Studios', 'Ubisoft', '2001-11-15', 'Donald Duck: Goin'' Quackers is a 2000 platform game developed and published by Ubi Soft for various consoles and Windows-based personal computers. A version with the same title was released for the Game Boy Color, before it was retitled Donald Duck Advance for the Game Boy Advance. Reviews praised the music, backgrounds and animations, noting the short length and low difficulty as more fun for children.', 'https://media.retroachievements.org/Images/125240.png', 'https://media.retroachievements.org/Images/097504.png', 'https://media.retroachievements.org/Images/097502.png', 'https://media.retroachievements.org/Images/097503.png', 4.1),
  (171, 5747, 'The Lost Vikings', 'Game Boy Advance', 5, 653, 653, 653, 28, 0, NULL, 'Mass Media', 'Mass Media', '2003-01-01', 'The Lost Vikings is a 1993 puzzle-platform game developed by Silicon & Synapse and published by Interplay Productions. In the game, the player controls three separate vikings with different abilities. The three vikings must work together to finish each level and find their way back home.', 'https://media.retroachievements.org/Images/064700.png', 'https://media.retroachievements.org/Images/096971.png', 'https://media.retroachievements.org/Images/004621.png', 'https://media.retroachievements.org/Images/004622.png', 4.1),
  (172, 5720, 'LEGO Star Wars II: The Original Trilogy', 'Game Boy Advance', 5, 644, 644, 644, 54, 0, 'Action-Adventure', 'Amaze Entertainment', 'LucasArts | Lucasfilm', '2006-09-12', 'Lego Star Wars II: The Original Trilogy is a 2006 Lego-themed action-adventure game developed by Traveller''s Tales and published by LucasArts and TT Games Publishing, and is the sequel to Lego Star Wars: The Video Game (2005). Part of the Lego Star Wars series, it is based on George Lucas''s movie franchise of the same name and The Lego Group''s Lego Star Wars construction toy line. It follows the events of the first three original Star Wars films: A New Hope (1977), The Empire Strikes Back (1980), and Return of the Jedi (1983). The game allows players to assume the roles of over 50 Lego versions of characters from the film series; customized characters can also be created. Camera movement was improved from its predecessor, and the concept of "vehicle levels" was explored more thoroughly. The game was revealed at American International Toy Fair. Promotions for the game were set up at chain stores across the United States.', 'https://media.retroachievements.org/Images/064198.png', 'https://media.retroachievements.org/Images/004775.png', 'https://media.retroachievements.org/Images/004776.png', 'https://media.retroachievements.org/Images/004777.png', 4),
  (173, 9301, 'Frogger''s Adventures: Temple of the Frog', 'Game Boy Advance', 5, 638, 638, 638, 26, 0, '2.5D Platforming', 'Konami', 'Konami', '2001-11-22', 'Frogger''s Adventures: Temple of the Frog is a 2001 platform video game developed and published by Konami for the Game Boy Advance. It was followed by Frogger''s Adventures 2: The Lost Wand in 2002 for the same console. In 2003, another game titled Frogger''s Adventures: The Rescue appeared for PlayStation 2, GameCube and Windows.', 'https://media.retroachievements.org/Images/067742.png', 'https://media.retroachievements.org/Images/061358.png', 'https://media.retroachievements.org/Images/061359.png', 'https://media.retroachievements.org/Images/061357.png', 4),
  (174, 6950, 'Jet Grind Radio', 'Game Boy Advance', 5, 623, 623, 623, 68, 0, '2.5D Platforming, Extreme Sports - Inline Skating', 'Vicarious Visions', 'Sega, THQ', '2003-06-26', 'Jet Set Radio is a 2000 action-platform video game developed by Smilebit and published by Sega for the Dreamcast. The player controls a member of the GG''s, a youth gang that uses inline skates to traverse Tokyo while spraying graffiti, challenging rival gangs, and evading authorities.', 'https://media.retroachievements.org/Images/052346.png', 'https://media.retroachievements.org/Images/052362.png', 'https://media.retroachievements.org/Images/052358.png', 'https://media.retroachievements.org/Images/052361.png', 4),
  (175, 8038, '~Homebrew~ Sushi the Cat', 'Game Boy Advance', 5, 620, 620, 620, 7, 0, '2D Platforming', 'N3TKAT', 'N3TKAT', '2007-11-12', 'Earthworm Jim is a 1994 run and gun platform game developed by Shiny Entertainment, featuring an earthworm named Jim, who wears a robotic suit and battles the forces of evil. The game was released for the Sega Genesis and Super Nintendo Entertainment System, before being subsequently ported to several other video game consoles.', 'https://media.retroachievements.org/Images/051052.png', 'https://media.retroachievements.org/Images/051314.png', 'https://media.retroachievements.org/Images/052002.png', 'https://media.retroachievements.org/Images/052003.png', 4),
  (176, 5029, 'Tactics Ogre: The Knight of Lodis', 'Game Boy Advance', 5, 613, 613, 613, 87, 0, 'Tactical RPG', 'Quest', 'Atlus', '2002-05-07', 'Tactics Ogre: The Knight of Lodis is a tactical role-playing game developed by Quest Corporation and published by Nintendo for the Game Boy Advance (GBA). It was released in Japan in 2001, and in North America by Atlus USA in 2002. It is a spin-off of Tactics Ogre (1995), acting as a prequel to the rest of the Ogre Battle series. It was the last video game developed by Quest before their acquisition by Square.', 'https://media.retroachievements.org/Images/066976.png', 'https://media.retroachievements.org/Images/010137.png', 'https://media.retroachievements.org/Images/033741.png', 'https://media.retroachievements.org/Images/025129.png', 4),
  (177, 25306, '~Homebrew~ Neo Racing Genesis', 'Game Boy Advance', 5, 611, 611, 611, 7, 0, 'Arcade Racing', 'Dan Prati', NULL, '2001-12-27', 'The following is a list of notable vehicle racing video games. The genre first emerged in the mid- to late 1970s.', 'https://media.retroachievements.org/Images/079052.png', 'https://media.retroachievements.org/Images/087381.png', 'https://media.retroachievements.org/Images/079051.png', 'https://media.retroachievements.org/Images/079053.png', 4),
  (178, 749, 'Classic NES Series: Zelda II: The Adventure of Link', 'Game Boy Advance', 5, 606, 606, 606, 29, 0, 'Action RPG', 'Nintendo', 'Nintendo', '2004-08-10', 'Zelda II: The Adventure of Link is a 1987 action role-playing game developed and published by Nintendo. It is the second installment in the Legend of Zelda series, and was released in Japan for the Famicom Disk System on January 14, 1987, less than a year after the Japanese release and seven months before the North American release of the original The Legend of Zelda. Zelda II was released in North America and the PAL region for the Nintendo Entertainment System in late 1988, almost two years after its initial release in Japan.', 'https://media.retroachievements.org/Images/045977.png', 'https://media.retroachievements.org/Images/001384.png', 'https://media.retroachievements.org/Images/001389.png', 'https://media.retroachievements.org/Images/001390.png', 4),
  (179, 7191, 'The Lord of the Rings: The Return of the King', 'Game Boy Advance', 5, 595, 595, 595, 57, 0, 'Action RPG', 'Griptonite Games', 'Electronic Arts', '2003-11-05', 'The Lord of the Rings: The Return of the King is a 2003 epic fantasy film directed by Peter Jackson from a screenplay he wrote with Fran Walsh and Philippa Boyens. It is based on 1955''s The Return of the King, the third volume of the novel The Lord of the Rings by J. R. R. Tolkien. The sequel to 2002''s  The Lord of the Rings: The Two Towers, the film is the final instalment in The Lord of the Rings trilogy. It has an ensemble cast including Elijah Wood, Ian McKellen, Liv Tyler, Viggo Mortensen, Sean Astin, Cate Blanchett, John Rhys-Davies, Bernard Hill, Billy Boyd, Dominic Monaghan, Orlando Bloom, Hugo Weaving, Miranda Otto, David Wenham, Karl Urban, John Noble, Andy Serkis, Ian Holm, and Sean Bean. Continuing the plot of the previous film, Frodo and Sam follow Gollum towards Mount Doom to destroy the One Ring, unaware of Gollum''s intentions to betray the duo to take the Ring for himself, while Merry, Pippin, Gandalf, Aragorn, Legolas, Gimli and their allies join forces against Sauron and his legions from Mordor.', 'https://media.retroachievements.org/Images/053150.png', 'https://media.retroachievements.org/Images/053151.png', 'https://media.retroachievements.org/Images/008493.png', 'https://media.retroachievements.org/Images/008491.png', 4),
  (180, 2190, 'Yu-Gi-Oh! GX: Duel Academy', 'Game Boy Advance', 5, 595, 595, 595, 41, 0, 'Collectible Card Game', 'Konami', 'Konami', '2006-01-10', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/094383.png', 'https://media.retroachievements.org/Images/024089.png', 'https://media.retroachievements.org/Images/026285.png', 'https://media.retroachievements.org/Images/003132.png', 4),
  (181, 16160, '~Hack~ Hypno''s Lullaby', 'Game Boy Advance', 5, 593, 593, 593, 8, 0, 'Turn-Based RPG', '7G06', NULL, '2012-12-09', 'Twitch Plays Pokémon (TPP) is a social experiment and channel on the video game live streaming website Twitch, consisting of a crowdsourced attempt to play Game Freak''s and Nintendo''s Pokémon video games by parsing commands sent by users through the channel''s chat room. It holds the Guinness World Record for having "the most users to input a command to play a live streamed videogame" with 1,165,140 participants.', 'https://media.retroachievements.org/Images/088908.png', 'https://media.retroachievements.org/Images/033128.png', 'https://media.retroachievements.org/Images/033130.png', 'https://media.retroachievements.org/Images/033131.png', 4),
  (182, 5564, 'Yu Yu Hakusho: Ghost Files - Tournament Tactics', 'Game Boy Advance', 5, 587, 587, 587, 60, 0, 'Tactical RPG', 'Sensory Sweep Studios', 'Atari', '2004-01-01', 'YuYu Hakusho  is a Japanese manga series written and illustrated by Yoshihiro Togashi. It was serialized in Shueisha''s shōnen manga magazine Weekly Shōnen Jump from December 1990 to July 1994. It consists of 175 chapters collected in 19 tankōbon volumes.', 'https://media.retroachievements.org/Images/085611.png', 'https://media.retroachievements.org/Images/085112.png', 'https://media.retroachievements.org/Images/113691.png', 'https://media.retroachievements.org/Images/113692.png', 4),
  (183, 4707, 'Shining Force: Resurrection of the Dark Dragon', 'Game Boy Advance', 5, 585, 585, 585, 72, 0, 'Tactical RPG', 'Amusement Vision', 'Sega, Atlus', '2004-06-08', 'Shining Force: The Legacy of Great Intention, commonly referred to as Shining Force, is a 1992 turn-based tactical role-playing game developed by Climax Entertainment and Sonic! Software Planning and published by Sega for the Sega Genesis. It is the second entry of the Shining series, following 1991''s Shining in the Darkness. While primarily a traditional fantasy-themed game, it contains some science fiction elements.', 'https://media.retroachievements.org/Images/082398.png', 'https://media.retroachievements.org/Images/018295.png', 'https://media.retroachievements.org/Images/018293.png', 'https://media.retroachievements.org/Images/018294.png', 4),
  (184, 7644, 'Avatar: The Last Airbender', 'Game Boy Advance', 5, 583, 583, 583, 46, 0, 'Action-Adventure', 'Halfbrick Studios', 'THQ', '2006-10-10', 'Avatar: The Last Airbender, also known as Avatar: The Legend of Aang in some regions, is an American animated fantasy action television series created by Michael Dante DiMartino and Bryan Konietzko. Produced by Nickelodeon Animation Studio, it originally aired on Nickelodeon for three seasons from February 2005 to July 2008.', 'https://media.retroachievements.org/Images/076401.png', 'https://media.retroachievements.org/Images/023527.png', 'https://media.retroachievements.org/Images/023531.png', 'https://media.retroachievements.org/Images/023532.png', 4),
  (185, 6141, 'Crash of the Titans', 'Game Boy Advance', 5, 579, 579, 579, 56, 0, '2D Platforming', 'Amaze Entertainment', 'Sierra Entertainment', '2007-10-04', 'Crash of the Titans is a 2007 platform game developed by Radical Entertainment and published by Vivendi Games for the PlayStation 2, PlayStation Portable, Wii and Xbox 360. The sixth mainline game in the Crash Bandicoot series, it was the last to be published by Vivendi Games before Activision merged with the company the following year. Amaze Entertainment developed two separate versions of the game: one for the Nintendo DS and one for the Game Boy Advance. The game is the fourteenth installment in the Crash Bandicoot video game series, and the sixth game in the main franchise.', 'https://media.retroachievements.org/Images/122803.png', 'https://media.retroachievements.org/Images/096969.png', 'https://media.retroachievements.org/Images/006712.png', 'https://media.retroachievements.org/Images/033827.png', 4),
  (186, 9877, '~Hack~ Pokémon Theta Emerald Renev', 'Game Boy Advance', 5, 577, 577, 577, 138, 0, 'Turn-Based RPG', 'LCCoolJ95', 'Hack - Pokemon Emerald Version', '2018-01-01', NULL, 'https://media.retroachievements.org/Images/031416.png', 'https://media.retroachievements.org/Images/044483.png', 'https://media.retroachievements.org/Images/029377.png', 'https://media.retroachievements.org/Images/016122.png', 4),
  (187, 774, 'Mega Man Battle Network 3: Blue Version', 'Game Boy Advance', 5, 575, 575, 575, 79, 0, 'Action RPG', 'Capcom', 'Capcom', '2003-06-24', 'Mega Man Battle Network is a tactical role-playing video game series created by Masahiro Yasuma and developed and published by Capcom as a spin-off of the Mega Man series. Released in 2001 for the Game Boy Advance, it takes place in an alternate continuity of Mega Man where computers and networking technology was the main focus on scientific advancement, rather than robotics. There are a total of six mainline games, alongside several spin-offs.', 'https://media.retroachievements.org/Images/102929.png', 'https://media.retroachievements.org/Images/039350.png', 'https://media.retroachievements.org/Images/033800.png', 'https://media.retroachievements.org/Images/039349.png', 4),
  (188, 12786, 'Dora the Explorer: The Search for Pirate Pig''s Treasure', 'Game Boy Advance', 5, 572, 572, 572, 37, 0, 'Adventure', 'Cinegroupe', 'NewKidCo', '2002-12-13', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/016907.png', 'https://media.retroachievements.org/Images/016906.png', 'https://media.retroachievements.org/Images/016905.png', 'https://media.retroachievements.org/Images/016908.png', 4),
  (189, 6087, 'Pocky & Rocky with Becky', 'Game Boy Advance', 5, 551, 551, 551, 36, 0, NULL, 'Altron', 'Natsume', '2001-10-05', 'Pocky & Rocky with Becky, known in Japan as Kiki Kaikai Advance (奇々怪界あどばんす), is a shoot ''em up video game for the Game Boy Advance handheld game console where the player may control either Pocky, Rocky, or Becky, the latter originating from the spin-off KiKi KaiKai: Dotou-hen, as they attempt to defeat a ghostly hydra who escaped his seal. The player character takes two hits to lose a life, but only one in Japan. While prior entries were developed by Taito, this game was developed and published by Altron in Japan, and published by Natsume Inc. in North America.', 'https://media.retroachievements.org/Images/122421.png', 'https://media.retroachievements.org/Images/049833.png', 'https://media.retroachievements.org/Images/049811.png', 'https://media.retroachievements.org/Images/049812.png', 4),
  (190, 9842, '~Hack~ Super Metroid: GBA Edition', 'Game Boy Advance', 5, 548, 548, 548, 46, 0, 'Metroidvania', 'The Brothers Crafters', 'Hack - Metroid: Zero Mission', '2020-12-15', 'Metroid is an action-adventure game franchise created by Nintendo. The player controls the bounty hunter Samus Aran, who protects the galaxy from Space Pirates and their attempts to harness the power of the parasitic Metroid creatures. Metroid combines the platforming of Super Mario Bros. and the exploration of The Legend of Zelda with a science fiction setting and an emphasis on nonlinear gameplay. Most Metroid games are side-scrolling, while the 3D games use a first-person perspective. Players battle hostile alien enemies and obtain power-ups as they progress through the game world, with few non-player characters.', 'https://media.retroachievements.org/Images/060092.png', 'https://media.retroachievements.org/Images/051199.png', 'https://media.retroachievements.org/Images/042049.png', 'https://media.retroachievements.org/Images/042050.png', 4),
  (191, 24054, 'SpongeBob''s Atlantis SquarePantis', 'Game Boy Advance', 5, 548, 548, 548, 29, 0, '2D Platforming', 'Altron', 'THQ', '2007-10-23', 'SpongeBob''s Atlantis SquarePantis is the first television film and the 92nd episode of the American animated television series SpongeBob SquarePants, and a 2007 made-for-television musical comedy film directed by Andrew Overtoom. It first aired on Nickelodeon in the United States on November 12, 2007, serving as the twelfth episode of the fifth season of the American animated television series SpongeBob SquarePants. It released again on November 23, 2007 with Patchy segments. In the special, SpongeBob and Patrick discover a half of an ancient medallion that helps them and their friends get to the lost city of Atlantis. It was written by Casey Alexander, Zeus Cervas, Steven Banks, and Dani Michaeli. British musician and actor David Bowie guest starred as the voice of Lord Royal Highness. Upon release, it attracted an estimated 9.22 million viewers, becoming the most watched episode of the entire series. Despite this, it received mixed reviews from critics and audiences alike, while the Patchy subplot received mixed to negative reviews.', 'https://media.retroachievements.org/Images/116267.png', 'https://media.retroachievements.org/Images/071379.png', 'https://media.retroachievements.org/Images/071377.png', 'https://media.retroachievements.org/Images/071378.png', 4),
  (192, 4738, 'The King of Fighters EX: Neo Blood', 'Game Boy Advance', 5, 545, 545, 545, 28, 0, '2D Fighting', 'SNK', 'SNK', '2002-01-01', 'The King of Fighters EX: Neo Blood is a fighting game developed by Playmore and Artoon in 2002 for Nintendo''s Game Boy Advance. Despite being based on The King of Fighters ''99 in terms of systems and design, the game features different playable characters with an original storyline involving Kyo Kusanagi and his friends being the protagonist of a new "King of Fighters" tournament set by crimelord Geese Howard. The game offers several returning characters with Kyo''s ally Moe Habana being a new character. Despite SNK going bankrupt, there were no issues with the development of the game, with Marvelous Entertainment developing it. The game received positive response by critics for its controls and cast and was followed by a sequel titled The King of Fighters EX2: Howling Blood in 2003.', 'https://media.retroachievements.org/Images/079759.png', 'https://media.retroachievements.org/Images/006970.png', 'https://media.retroachievements.org/Images/006967.png', 'https://media.retroachievements.org/Images/006968.png', 4),
  (193, 4881, 'DemiKids: Dark Version', 'Game Boy Advance', 5, 542, 542, 542, 81, 0, 'Turn-Based RPG', 'Multimedia Intelligence Transfer', 'Atlus', '2003-10-07', 'Shin Megami Tensei: Devil Children, also known as DemiKids, is a series of role-playing video games primarily developed by Multimedia Intelligence Transfer and published by Atlus. It is a spin-off from Atlus'' Megami Tensei franchise, and began in 2000 with the Game Boy Color games Black Book and Red Book. Five more role-playing games and three games in other genres were released until 2004, followed by no new releases until the 2011 social game Shin Megami Tensei: Devil Children. In addition to the games, the series has been adapted into manga, anime, and a trading card game, and two soundtrack albums have been released by First Smile Entertainment.', 'https://media.retroachievements.org/Images/082326.png', 'https://media.retroachievements.org/Images/007855.png', 'https://media.retroachievements.org/Images/033773.png', 'https://media.retroachievements.org/Images/007854.png', 4),
  (194, 6620, 'Zooo: Action Puzzle Game', 'Game Boy Advance', 5, 541, 541, 541, 22, 0, 'Tile Matching', 'Buddiez', 'Ignition Entertainment', '2003-10-31', 'This is a list of games released on the Game Boy Advance handheld video game system. The number of licensed games in this list is 1538, organized alphabetically by the games'' localized English titles, or, when Japan-exclusive, their rōmaji transliterations. This list does not include Game Boy Advance Video releases.', 'https://media.retroachievements.org/Images/036704.png', 'https://media.retroachievements.org/Images/107671.png', 'https://media.retroachievements.org/Images/036701.png', 'https://media.retroachievements.org/Images/036702.png', 4),
  (195, 6772, 'Scooby-Doo! Unmasked', 'Game Boy Advance', 5, 537, 537, 537, 28, 0, '2D Platforming', 'Artificial Mind and Movement', 'THQ', '2005-09-12', 'Scooby-Doo! Unmasked is a platform game based on the Scooby-Doo franchise. It was developed by Artificial Mind and Movement and published by THQ for the Xbox, PlayStation 2, GameCube, Game Boy Advance, and Nintendo DS.', 'https://media.retroachievements.org/Images/108667.png', 'https://media.retroachievements.org/Images/011165.png', 'https://media.retroachievements.org/Images/011167.png', 'https://media.retroachievements.org/Images/011168.png', 4),
  (196, 761, 'Earthworm Jim', 'Game Boy Advance', 5, 531, 531, 531, 59, 0, '2D Platforming', 'Shiny Entertainment, Game Titan', 'Interplay Entertainment', '2001-06-10', 'Earthworm Jim is a series of platform games featuring an earthworm named Jim who wears a robotic suit and battles the forces of evil. The series is noted for its platforming and shooting gameplay, surreal humor, and edgy art style. Four games were released in the series: Earthworm Jim, Earthworm Jim 2, Earthworm Jim 3D, and Earthworm Jim: Menace 2 the Galaxy, with the first game released in 1994. The series had lain dormant for almost a decade before Gameloft remade the original game in HD for PlayStation Network and Xbox Live Arcade in 2010. Interplay announced Earthworm Jim 4 in 2008; little to no information surfaced until May 2019 and August 2020, and development was believed cancelled by the rights owners by 2023, as it had never left pre-planning stages.', 'https://media.retroachievements.org/Images/121734.png', 'https://media.retroachievements.org/Images/093959.png', 'https://media.retroachievements.org/Images/089684.png', 'https://media.retroachievements.org/Images/089685.png', 4),
  (197, 2589, 'Summon Night: Swordcraft Story 2', 'Game Boy Advance', 5, 530, 530, 530, 81, 0, NULL, 'Flight-Plan', 'Atlus', '2006-10-17', 'Summon Night: Swordcraft Story 2  is a 2004 action role-playing game developed by Flight-Plan for the Game Boy Advance. It is part of the Summon Night series of games, and is the sequel to Summon Night: Swordcraft Story. The game was first released in Japan by Banpresto in August 2004, and in North America by Atlus in October 2006. The game received generally favorable reviews. It was followed by Summon Night Swordcraft Story 3: Stone of Beginnings, released in December 2005.', 'https://media.retroachievements.org/Images/122120.png', 'https://media.retroachievements.org/Images/011161.png', 'https://media.retroachievements.org/Images/011162.png', 'https://media.retroachievements.org/Images/011163.png', 4),
  (198, 6759, 'Denki Blocks!', 'Game Boy Advance', 5, 525, 525, 525, 33, 0, NULL, 'Rage Software', 'Majesco Entertainment', '2001-10-30', 'Denki Blocks! is a puzzle video game developed by Denki and originally released in 2001 by Rage Games for Sky Gamestar and the Game Boy Color and Game Boy Advance. In the game, players manoeuvre different coloured blocks around a grid to join those of the same colour together. The game features versus modes for multiple players. Denki Blocks! was ported to the PlayStation Portable in 2011 by Tiger Games, and to Android the same year and iOS in 2010.', 'https://media.retroachievements.org/Images/116149.png', 'https://media.retroachievements.org/Images/014443.png', 'https://media.retroachievements.org/Images/116148.png', 'https://media.retroachievements.org/Images/006659.png', 4),
  (199, 2172, 'Mortal Kombat: Deadly Alliance', 'Game Boy Advance', 5, 525, 525, 525, 57, 0, '3D Fighting', 'Midway', 'Midway', '2002-11-20', 'Mortal Kombat: Deadly Alliance is a 2002 fighting game developed and published by Midway for the Xbox, PlayStation 2 (PS2), GameCube, and Game Boy Advance (GBA). It was the first all-new Mortal Kombat fighting game produced exclusively for home consoles, with no preceding arcade release. It is the fifth main installment in the Mortal Kombat franchise and a sequel to 1997''s Mortal Kombat 4. Its story focuses on the eponymous alliance between sorcerers Quan Chi and Shang Tsung and their schemes to revive an ancient army to conquer Outworld and Earthrealm. The game is the only main installment not to feature series protagonist Liu Kang as a playable character. It is also the first game in the canon series to not have the involvement of co-creator John Tobias, who had left Midway in 1999 to pursue other interests.', 'https://media.retroachievements.org/Images/073151.png', 'https://media.retroachievements.org/Images/012070.png', 'https://media.retroachievements.org/Images/012074.png', 'https://media.retroachievements.org/Images/012075.png', 4),
  (200, 4909, 'Mega Man Battle Chip Challenge', 'Game Boy Advance', 5, 523, 523, 523, 32, 0, NULL, 'Inti Creates', 'Capcom', '2004-03-03', 'Mega Man Battle Chip Challenge, known in Japan as Rockman EXE Battle Chip GP, is a video game developed by Inti Creates and published by Capcom for the Game Boy Advance (GBA) handheld game console. It is a spin-off title in the Mega Man Battle Network series. The game saw a simultaneous August 8, 2003 release in Japan on the WonderSwan Color and Swan Crystal titled Rockman EXE N1 Battle. The GBA version was localized in North America and Europe the following March. The game was released on the Wii U''s Virtual Console on July 30, 2014 in Japan, with both the North American and PAL region release occurring in August 2014.', 'https://media.retroachievements.org/Images/038243.png', 'https://media.retroachievements.org/Images/040305.png', 'https://media.retroachievements.org/Images/003046.png', 'https://media.retroachievements.org/Images/003047.png', 4);
